:root {
  /* Modern Slate & Indigo Palette */
  --primary-color: #4f46e5; /* Indigo 600 */
  --primary-dark: #4338ca;  /* Indigo 700 */
  --primary-light: #e0e7ff; /* Indigo 100 */

  --bg-color: #f8fafc;      /* Slate 50 */
  --card-bg: #ffffff;

  --text-main: #0f172a;     /* Slate 900 */
  --text-secondary: #475569; /* Slate 600 */
  --text-light: #94a3b8;    /* Slate 400 */

  --border-color: #e2e8f0;  /* Slate 200 */

  --danger-color: #ef4444;  /* Red 500 */
  --success-color: #10b981; /* Emerald 500 */
  --warning-color: #f59e0b; /* Amber 500 */
  --abatement-color: #8b5cf6; /* Violet 500 */

  /* Modern Shadows */
  --shadow-sm: 0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);

  --radius-md: 8px;
  --radius-lg: 12px;
  --radius-xl: 16px;

  --header-height: 60px;

  --font-family: 'Roboto', system-ui, -apple-system, sans-serif;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: var(--font-family);
  background-color: var(--bg-color);
  color: var(--text-main);
  line-height: 1.5;
  font-size: 15px;
  padding-bottom: 80px;
}

/* --- Header --- */
.app-header {
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(10px);
  color: var(--text-main);
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 1rem;
  position: sticky;
  top: 0;
  z-index: 100;
  border-bottom: 1px solid var(--border-color);
  justify-content: space-between;
}

.app-header h1 {
  font-size: 1.15rem;
  font-weight: 700;
  margin: 0;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  text-align: center;
  flex-grow: 1;
  padding: 0 0.5rem;
  background: linear-gradient(to right, var(--primary-color), var(--abatement-color));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

/* --- Layout --- */
.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

#root {
  max-width: 100%;
}

@media (min-width: 1024px) {
    #root {
        max-width: 1024px;
        margin: 0 auto;
        background: var(--bg-color);
        min-height: 100vh;
    }
}

/* --- Navigation --- */
.main-nav {
  display: flex;
  overflow-x: auto;
  background-color: var(--bg-color); /* Match body bg for floating tab look */
  padding: 0.5rem 1rem;
  position: sticky;
  top: var(--header-height);
  z-index: 90;
  scrollbar-width: none;
  height: 56px;
  align-items: center;
  gap: 0.5rem;
}

.main-nav::-webkit-scrollbar { display: none; }

.main-nav button {
  flex: 0 0 auto;
  padding: 0.4rem 1rem;
  border: 1px solid transparent;
  background: var(--card-bg);
  color: var(--text-secondary);
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  border-radius: 99px; /* Pill shape */
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  white-space: nowrap;
  box-shadow: var(--shadow-sm);
}

.main-nav button.active {
  background-color: var(--text-main);
  color: white;
  transform: translateY(-1px);
  box-shadow: var(--shadow-md);
}

/* --- Content Area --- */
.main-content {
  padding: 0.5rem 1rem 1rem 1rem;
  width: 100%;
}

.tab-content {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  animation: fadeIn 0.3s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(5px); }
  to { opacity: 1; transform: translateY(0); }
}

/* --- Cards --- */
.card {
  background-color: var(--card-bg);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  padding: 1.25rem;
  border: 1px solid var(--border-color);
  transition: box-shadow 0.2s;
}

.card:hover {
  box-shadow: var(--shadow-md);
}

.card h2 {
  font-size: 1.1rem;
  color: var(--text-main);
  margin-bottom: 1rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.card h3 {
  font-size: 1rem;
  color: var(--text-main);
  margin-top: 1.25rem;
  margin-bottom: 0.75rem;
  font-weight: 600;
  letter-spacing: -0.01em;
}

/* --- Lists & Items --- */
.case-item {
  background: white;
  padding: 1rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  margin-bottom: 0.75rem;
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
  overflow: hidden;
}

.case-item:hover {
  transform: translateY(-1px);
  box-shadow: var(--shadow-sm);
  border-color: var(--primary-light);
}

.case-item:active { 
  background-color: var(--bg-color); 
  transform: scale(0.99);
}

/* Status Indicators */
.case-item::before {
    content: '';
    position: absolute;
    left: 0; top: 0; bottom: 0; width: 4px;
    background-color: var(--text-light); /* Default */
}

.case-item.overdue::before { background-color: var(--warning-color); }
.case-item.abatement::before { background-color: var(--abatement-color); }
.case-item.continual-abatement::before { background-color: var(--abatement-color); }
.case-item.ontime::before { background-color: var(--success-color); }
.case-item.closed::before { background-color: var(--border-color); }
.case-item.closed { opacity: 0.75; background-color: #f8fafc; }


.case-info strong {
    font-size: 1.05rem;
    color: var(--text-main);
    display: block;
    margin-bottom: 0.1rem;
}
.case-info span {
    font-size: 0.85rem;
    color: var(--text-secondary);
}

.status-badge {
    font-size: 0.7rem;
    padding: 2px 8px;
    border-radius: 99px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.02em;
    display: inline-block;
}
.status-badge.unknown-owner { background-color: #fef08a; color: #854d0e; }

/* --- Buttons --- */
.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.6rem 1.25rem;
  border-radius: var(--radius-md);
  border: none;
  background-color: var(--primary-color);
  color: white;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
  min-height: 40px;
  line-height: 1.2;
  text-decoration: none;
  white-space: nowrap;
  box-shadow: 0 1px 2px rgba(0,0,0,0.05);
}

.button:hover { background-color: var(--primary-dark); transform: translateY(-1px); box-shadow: var(--shadow-md); }
.button:active { transform: translateY(0); }
.button:disabled { background-color: var(--text-light); cursor: not-allowed; transform: none; box-shadow: none; opacity: 0.7; }

.button.full-width { width: 100%; }

.button.secondary-action {
  background-color: white;
  color: var(--text-main);
  border: 1px solid var(--border-color);
  box-shadow: var(--shadow-sm);
}
.button.secondary-action:hover { background-color: var(--bg-color); border-color: var(--text-light); }

.button.danger-action { background-color: var(--danger-color); color: white; }
.button.danger-action:hover { background-color: #dc2626; }

.button.primary-action { background-color: var(--primary-color); }

.button-group {
  display: flex;
  gap: 0.75rem;
  margin-top: 1.25rem;
  flex-wrap: wrap;
}

/* --- Forms --- */
.form-group {
  margin-bottom: 1.25rem;
}

.form-group label {
  display: block;
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--text-secondary);
  margin-bottom: 0.4rem;
  letter-spacing: 0.01em;
}

input[type="text"],
input[type="number"],
input[type="date"],
input[type="tel"],
input[type="email"],
select,
textarea {
  width: 100%;
  padding: 0.6rem 0.8rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  font-size: 1rem;
  background-color: #fff;
  color: var(--text-main);
  min-height: 44px;
  transition: all 0.2s;
}

input:focus, select:focus, textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px var(--primary-light);
}

.input-with-button {
    display: flex;
    gap: 0.5rem;
}
.input-with-button input { flex-grow: 1; }

.readonly .form-value {
    padding: 0.5rem 0;
    font-size: 1rem;
    color: var(--text-main);
    border-bottom: 1px solid var(--border-color);
    margin-bottom: 0.25rem;
}

/* --- Search Bar --- */
.search-bar {
    position: relative;
    margin-bottom: 1rem;
}
.search-bar input {
    padding-left: 2.75rem;
    border-radius: 99px;
    background-color: white;
    border: 1px solid var(--border-color);
    height: 48px;
    box-shadow: var(--shadow-sm);
}
.search-icon {
    position: absolute;
    left: 1rem;
    top: 50%;
    transform: translateY(-50%);
    color: var(--text-light);
    pointer-events: none;
}

/* --- Stepper --- */
.stepper {
  display: flex;
  justify-content: space-between;
  margin: 0.5rem 0 2rem 0;
  padding: 0;
  position: relative;
}
.stepper::before {
  content: '';
  position: absolute;
  top: 18px;
  left: 20px;
  right: 20px;
  height: 3px;
  background: var(--border-color);
  z-index: 0;
  border-radius: 3px;
}
.step {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  cursor: pointer;
  flex: 1;
}
.step-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: white;
  border: 3px solid var(--border-color);
  color: var(--text-light);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 1rem;
  margin-bottom: 0.5rem;
  transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
  box-shadow: var(--shadow-sm);
}
.step.active .step-circle {
  border-color: var(--abatement-color);
  background-color: var(--abatement-color);
  color: white;
  transform: scale(1.15);
  box-shadow: 0 0 0 4px rgba(139, 92, 246, 0.2);
}
.step.completed .step-circle {
  background-color: var(--success-color);
  border-color: var(--success-color);
  color: white;
}
.step-label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.03em;
}
.step.active .step-label { color: var(--abatement-color); }

/* --- Timer --- */
.timer-display {
    background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
    color: white;
    padding: 2rem;
    border-radius: var(--radius-xl);
    text-align: center;
    margin: 1.5rem 0;
    box-shadow: var(--shadow-lg);
    border: 1px solid rgba(255,255,255,0.1);
}
.timer-count {
    font-size: 3.5rem;
    font-weight: 800;
    line-height: 1;
    font-feature-settings: "tnum";
    font-variant-numeric: tabular-nums;
    text-shadow: 0 2px 4px rgba(0,0,0,0.3);
}
.timer-label {
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    opacity: 0.7;
    margin-top: 0.5rem;
}
.timer-done { background: linear-gradient(135deg, #059669 0%, #047857 100%); }

/* --- Utilities --- */
.helper-text { font-size: 0.85rem; color: var(--text-secondary); margin-top: 0.25rem; }

.status-message, .warning-box, .info-box, .success-message, .error-message {
    padding: 1rem;
    border-radius: var(--radius-md);
    margin: 1rem 0;
    font-size: 0.95rem;
    display: flex;
    align-items: flex-start;
    gap: 0.5rem;
    line-height: 1.4;
}

.success-message { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
.error-message { background: #fee2e2; color: #991b1b; border: 1px solid #fecaca; }
.warning-box { background: #fef3c7; color: #92400e; border: 1px solid #fde68a; }
.info-box { background: #e0f2fe; color: #075985; border: 1px solid #bae6fd; }

.copyable-row {
    background: #f8fafc;
    padding: 0.75rem;
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
    font-size: 0.9rem;
}

.photo-gallery { display: flex; gap: 0.75rem; overflow-x: auto; padding-bottom: 0.5rem; margin-top: 0.75rem; }
.photo-thumbnail { 
    width: 90px; height: 90px; flex: 0 0 auto; 
    border-radius: var(--radius-md); overflow: hidden; 
    border: 1px solid var(--border-color); position: relative; 
    box-shadow: var(--shadow-sm);
}
.photo-thumbnail img { width: 100%; height: 100%; object-fit: cover; }
.photo-thumbnail .button { position: absolute; bottom: 0; right: 0; padding: 4px; border-radius: 4px; }

/* --- Camera Overlay --- */
.camera-overlay { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: black; z-index: 200; display: flex; flex-direction: column; }
.camera-video-wrapper { flex: 1; background: #000; display: flex; align-items: center; overflow: hidden; position: relative; }
.camera-video { width: 100%; height: 100%; object-fit: cover; }
.camera-controls { height: 140px; background: rgba(0,0,0,0.9); display: flex; align-items: center; justify-content: space-around; padding-bottom: 20px; }
.capture-button { width: 72px; height: 72px; border-radius: 50%; background: rgba(255,255,255,0.2); border: 4px solid white; display: flex; justify-content: center; align-items: center; transition: transform 0.1s; }
.capture-button:active { transform: scale(0.95); }
.capture-button-inner { width: 56px; height: 56px; background: white; border-radius: 50%; }
.camera-action-button { color: white; background: none; border: none; padding: 1rem; font-weight: 600; font-size: 1rem; }

/* Print */
@media print {
    .no-print, .app-header, .main-nav { display: none !important; }
    .app-container { display: block; height: auto; overflow: visible; }
    .card { box-shadow: none; border: 1px solid #000; break-inside: avoid; margin-bottom: 1rem; }
    body { font-size: 12pt; background: white; padding: 0; }
}

import React, { useState, useEffect, useMemo } from 'react';
import { Case } from '../types';
import { STREET_ORDER } from '../utils';
import * as dailyTaskService from '../dailyTaskService';
import { DailyProgress } from '../dailyTaskService';
import { generateCertificateOfMail } from '../googleSheetsService';

interface DailyTasksProps {
    cases: Case[];
    onSelectCase: (caseId: string) => void;
}

const CollapsibleCard: React.FC<{
    title: string;
    count?: number;
    children: React.ReactNode;
    defaultExpanded?: boolean;
    color?: string;
}> = ({ title, count, children, defaultExpanded = false, color }) => {
    const [expanded, setExpanded] = useState(defaultExpanded);

    return (
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
            <div 
                onClick={() => setExpanded(!expanded)} 
                style={{ 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center', 
                    cursor: 'pointer', 
                    padding: '1rem 1.25rem',
                    background: expanded ? 'white' : 'white',
                    borderBottom: expanded ? '1px solid var(--border-color)' : 'none',
                    borderLeft: color ? `4px solid ${color}` : '4px solid transparent'
                }}
            >
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <h2 style={{ margin: 0, border: 'none', fontSize: '1.05rem', color: 'var(--text-main)' }}>{title}</h2>
                    {count !== undefined && (
                        <span style={{ 
                            fontSize: '0.8rem', 
                            backgroundColor: count > 0 ? (color || 'var(--text-secondary)') : '#f1f5f9', 
                            color: count > 0 ? 'white' : 'var(--text-light)', 
                            padding: '2px 10px', 
                            borderRadius: '99px',
                            fontWeight: 600
                        }}>
                            {count}
                        </span>
                    )}
                </div>
                <span style={{ fontSize: '1.25rem', color: 'var(--text-light)', transition: 'transform 0.2s', transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)' }}>&#9662;</span>
            </div>
            {expanded && <div style={{ padding: '1.25rem', animation: 'fadeIn 0.2s' }}>{children}</div>}
        </div>
    );
};

const TaskItem: React.FC<{
    title: string;
    subtext?: string;
    onClick: () => void;
    statusClass?: string;
}> = ({ title, subtext, onClick, statusClass }) => (
    <div className={`case-item ${statusClass || ''}`} onClick={onClick} role="button" tabIndex={0} style={{display: 'flex', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', gap: '1rem'}}>
        <div className="case-info">
            <strong style={{ fontSize: '1rem' }}>{title}</strong>
            {subtext && <span style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>{subtext}</span>}
        </div>
        <div style={{ color: 'var(--text-light)' }}>
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"></polyline></svg>
        </div>
    </div>
);


const DailyTasks: React.FC<DailyTasksProps> = ({ cases, onSelectCase }) => {
    const [patrolIndex, setPatrolIndex] = useState(-1);
    const [todaysProgress, setTodaysProgress] = useState<DailyProgress>({ completedStreets: [], completedCaseTasks: {} });

    const [certQueue, setCertQueue] = useState<string[]>([]);
    const [isGeneratingCert, setIsGeneratingCert] = useState(false);
    const [certError, setCertError] = useState('');
    const [certSuccess, setCertSuccess] = useState('');

    useEffect(() => {
        dailyTaskService.checkAndRotatePatrol();
        setPatrolIndex(dailyTaskService.getPatrolState().lastCompletedIndex);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
        setCertQueue(dailyTaskService.getCertMailQueue());
    }, []);

    useEffect(() => {
        const refreshState = () => {
            const latestProgress = dailyTaskService.getTodaysProgress();
            setTodaysProgress(current => JSON.stringify(latestProgress) !== JSON.stringify(current) ? latestProgress : current);
            const latestQueue = dailyTaskService.getCertMailQueue();
            setCertQueue(current => JSON.stringify(latestQueue) !== JSON.stringify(current) ? latestQueue : current);
            const latestState = dailyTaskService.getPatrolState();
            setPatrolIndex(latestState.lastCompletedIndex);
        };
        window.addEventListener('focus', refreshState);
        return () => window.removeEventListener('focus', refreshState);
    }, []);


    const casesForCert = useMemo(() => {
        return cases.filter(c => certQueue.includes(c.id));
    }, [certQueue, cases]);

    const handleGenerateCertificate = async () => {
        if (casesForCert.length === 0) return;
        setIsGeneratingCert(true);
        setCertError('');
        setCertSuccess('');
        try {
            const generatedDocs = await generateCertificateOfMail(casesForCert);
            generatedDocs.forEach(doc => window.open(doc.docUrl, '_blank'));
            setCertSuccess(`Successfully generated ${generatedDocs.length} certificate document(s).`);
            dailyTaskService.clearCertMailQueue();
            setCertQueue([]);
        } catch (e: any) {
            setCertError(`Failed to generate certificate: ${e.message}`);
        } finally {
            setIsGeneratingCert(false);
        }
    };

    const handleRemoveFromQueue = (caseId: string) => {
        dailyTaskService.removeFromCertMailQueue(caseId);
        setCertQueue(current => current.filter(id => id !== caseId));
    };

    const handleAdvancePatrol = () => {
        dailyTaskService.advancePatrol(STREET_ORDER.length);
        const state = dailyTaskService.getPatrolState();
        state.lastRotationDate = new Date().toISOString().split('T')[0];
        dailyTaskService.savePatrolState(state);
        setPatrolIndex(state.lastCompletedIndex);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
    };

    const handleStreetToggle = (street: string, checked: boolean) => {
        dailyTaskService.markStreetComplete(street, checked);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
    };

    const handleEnvelopeToggle = (caseId: string, isComplete: boolean) => {
        dailyTaskService.setTaskComplete(caseId, 'envelope', isComplete);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
    };

    const now = new Date();
    const sevenDaysAgo = new Date(new Date().setDate(now.getDate() - 7));

    const newCases = cases.filter(c => 
        new Date(c.dateCreated) >= sevenDaysAgo && c.status !== 'CLOSED'
    ).sort((a,b) => new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime());

    const newCaseTasks = newCases.map(c => {
        const progress = todaysProgress.completedCaseTasks[c.id] || [];
        const noticeDone = c.notices.length > 0 || progress.includes('notice');
        const envelopeDone = progress.includes('envelope');
        return { ...c, noticeDone, envelopeDone, isComplete: noticeDone && envelopeDone };
    }).filter(c => !c.isComplete);

    const dueCases = cases.filter(c => {
        const deadline = new Date(c.complianceDeadline);
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        return deadline < today && c.status !== 'CLOSED' && c.status !== 'PENDING_ABATEMENT';
    });

    const abatementCases = cases.filter(c => c.status === 'PENDING_ABATEMENT');
    const currentPatrolIndex = patrolIndex === -1 ? 0 : patrolIndex;
    const streetsForPatrol = STREET_ORDER.slice(currentPatrolIndex, currentPatrolIndex + 3);

    return (
        <div className="tab-content">
            <style>{`
                .task-list { display: flex; flex-direction: column; gap: 0.75rem; }
                .task-item { 
                    display: flex; align-items: flex-start; justify-content: space-between; 
                    background: white; padding: 1rem; 
                    border: 1px solid var(--border-color); border-radius: var(--radius-md); 
                    transition: all 0.2s;
                }
                .task-item:hover { box-shadow: var(--shadow-sm); border-color: var(--primary-light); }
                .subtask-list { margin-top: 0.75rem; display: flex; flex-direction: column; gap: 0.5rem; }
                .subtask-item { 
                    display: flex; align-items: center; gap: 0.75rem; 
                    font-size: 0.9rem; color: var(--text-secondary);
                    padding: 0.25rem 0;
                }
                .subtask-item input { 
                    width: 1.1rem; height: 1.1rem; accent-color: var(--primary-color);
                    cursor: pointer;
                }
                .patrol-row {
                    display: flex; align-items: center; gap: 1rem;
                    padding: 0.75rem; border-bottom: 1px solid var(--border-color);
                }
                .patrol-row:last-child { border-bottom: none; }
                .patrol-row input { width: 1.25rem; height: 1.25rem; accent-color: var(--primary-color); }
                .patrol-label { flex-grow: 1; font-weight: 500; font-size: 1rem; color: var(--text-main); }
                .completed-task { text-decoration: line-through; color: var(--text-light); }
                .task-title { font-weight: 600; color: var(--primary-color); cursor: pointer; font-size: 1rem; }
            `}</style>

            {/* PATROL */}
            <div className="card">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                    <h2>Daily Patrol</h2>
                    <button className="button secondary-action" onClick={handleAdvancePatrol} style={{ padding: '0.4rem 0.75rem', fontSize: '0.8rem' }}>Skip Zone &rarr;</button>
                </div>
                <div style={{ backgroundColor: '#f8fafc', borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)' }}>
                    {streetsForPatrol.map(street => (
                        <div key={street} className="patrol-row">
                           <input 
                                type="checkbox"
                                id={`street-${street}`}
                                checked={todaysProgress.completedStreets.includes(street)}
                                onChange={e => handleStreetToggle(street, e.target.checked)}
                            />
                            <label htmlFor={`street-${street}`} className={`patrol-label ${todaysProgress.completedStreets.includes(street) ? 'completed-task' : ''}`}>
                                {street.toUpperCase()}
                            </label>
                        </div>
                    ))}
                </div>
            </div>

            {/* NEW CASES */}
            <CollapsibleCard title="New Cases" count={newCaseTasks.length} defaultExpanded={newCaseTasks.length > 0} color="var(--primary-color)">
                <div className="task-list">
                    {newCaseTasks.length > 0 ? newCaseTasks.map(c => (
                        <div key={c.id} className="task-item">
                            <div style={{flex: 1}}>
                                <div className="task-title" onClick={() => onSelectCase(c.id)}>{c.address.street}</div>
                                <div className="subtask-list">
                                    <label className={`subtask-item ${c.noticeDone ? 'completed-task' : ''}`}>
                                        <input type="checkbox" checked={c.noticeDone} readOnly />
                                        Initial Notice
                                    </label>
                                    <label className={`subtask-item ${c.envelopeDone ? 'completed-task' : ''}`}>
                                        <input
                                            type="checkbox"
                                            checked={c.envelopeDone}
                                            onChange={(e) => handleEnvelopeToggle(c.id, e.target.checked)}
                                        />
                                        Envelope
                                    </label>
                                </div>
                            </div>
                            <div onClick={() => onSelectCase(c.id)} style={{ cursor: 'pointer', padding: '0.5rem', color: 'var(--text-light)' }}>
                                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"></polyline></svg>
                            </div>
                        </div>
                    )) : <p style={{color: 'var(--text-light)', fontStyle: 'italic', textAlign: 'center'}}>All new cases processed.</p>}
                </div>
            </CollapsibleCard>

            {/* DUE CASES */}
            <CollapsibleCard title="Due for Follow-up" count={dueCases.length} defaultExpanded={dueCases.length > 0} color="var(--warning-color)">
                <div className="task-list">
                    {dueCases.length > 0 ? dueCases.map(c => (
                        <TaskItem 
                            key={c.id}
                            title={c.address.street}
                            subtext={`Deadline: ${c.complianceDeadline}`}
                            onClick={() => onSelectCase(c.id)}
                            statusClass="overdue"
                        />
                    )) : <p style={{color: 'var(--text-light)', fontStyle: 'italic', textAlign: 'center'}}>No cases currently due.</p>}
                </div>
            </CollapsibleCard>

            {/* ABATEMENT */}
            <CollapsibleCard title="Abatement" count={abatementCases.length} defaultExpanded={abatementCases.length > 0} color="var(--abatement-color)">
                <div className="task-list">
                    {abatementCases.length > 0 ? abatementCases.map(c => (
                        <TaskItem 
                            key={c.id}
                            title={c.address.street}
                            subtext={c.abatement?.status?.replace('_', ' ') || 'Pending'}
                            onClick={() => onSelectCase(c.id)}
                            statusClass="abatement"
                        />
                    )) : <p style={{color: 'var(--text-light)', fontStyle: 'italic', textAlign: 'center'}}>No active abatements.</p>}
                </div>
            </CollapsibleCard>

            {/* ADMIN */}
            <CollapsibleCard title="Mailing Queue" count={casesForCert.length} color="var(--text-secondary)">
                 <div className="task-list">
                    {casesForCert.length > 0 ? (
                        <>
                            <button className="button full-width" onClick={handleGenerateCertificate} disabled={isGeneratingCert}>
                                {isGeneratingCert ? <span className="loader" /> : `Generate Certificates (${casesForCert.length})`}
                            </button>
                            {certSuccess && <div className="success-message">{certSuccess}</div>}
                            {certError && <div className="error-message">{certError}</div>}
                            <div style={{marginTop: '0.5rem'}}>
                                {casesForCert.map(c => (
                                    <div key={c.id} className="copyable-row" style={{ marginTop: '0.5rem', padding: '0.5rem 0.75rem' }}>
                                        <span style={{fontSize: '0.9rem'}}>{c.address.street}</span>
                                        <button className="button danger-action" style={{padding: '0.2rem 0.5rem', fontSize: '0.75rem', height: 'auto'}} onClick={() => handleRemoveFromQueue(c.id)}>Remove</button>
                                    </div>
                                ))}
                            </div>
                        </>
                    ) : (
                        <p className="helper-text" style={{textAlign: 'center'}}>Queue empty.</p>
                    )}
                </div>
            </CollapsibleCard>
        </div>
    );
};

export default DailyTasks;

import React, { useState, useMemo } from 'react';
import { Case, AbatementStatus } from '../types';
import { getCaseTimeStatus, compareStreets } from '../utils';

const getStatusClass = (c: Case): string => {
    if (c.status === 'CLOSED') return 'closed';
    if (c.status === 'PENDING_ABATEMENT') return 'abatement';
    if (c.status === 'CONTINUAL_ABATEMENT') return 'continual-abatement';
    return getCaseTimeStatus(c);
};

interface CaseListProps {
    cases: Case[];
    onSelectCase: (caseId: string) => void;
    onNewCase: () => void;
    listType?: 'all' | 'due' | 'abatement' | 'continual-abatement';
    onGenerateReport?: () => void;
}

const CaseItemRow: React.FC<{ c: Case; onSelect: () => void; showExpiry?: boolean; subtitle?: string; badge?: string; badgeColor?: string }> = ({ c, onSelect, showExpiry, subtitle, badge, badgeColor }) => {
    const statusClass = getStatusClass(c);

    let displayStatus = '';
    if (c.status === 'PENDING_ABATEMENT') displayStatus = 'Abatement';
    else if (c.status === 'CONTINUAL_ABATEMENT') displayStatus = 'Continual';
    else if (c.status === 'CLOSED') displayStatus = 'Closed';
    else displayStatus = 'Active';

    let expiryDateText = '';
    if (showExpiry && c.abatement?.workDate) {
        const workDate = new Date(c.abatement.workDate.replace(/-/g, '\/'));
        if (!isNaN(workDate.getTime())) {
            workDate.setMonth(workDate.getMonth() + 6);
            expiryDateText = `Expires: ${workDate.toLocaleDateString()}`;
        }
    }

    return (
        <div className={`case-item ${statusClass}`} onClick={onSelect} role="button" tabIndex={0} aria-label={`View case ${c.caseId}`}>
            <div className="case-info">
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.2rem'}}>
                    <strong>{c.address.street}</strong>
                    {badge ? (
                        <span className="status-badge" style={{backgroundColor: badgeColor || 'var(--primary-color)', color:'white'}}>{badge}</span>
                    ) : (
                        <span style={{ fontSize: '0.75rem', color: 'var(--text-light)', fontWeight: 500 }}>{displayStatus.toUpperCase()}</span>
                    )}
                </div>

                {c.ownerInfoStatus === 'UNKNOWN' && (
                     <span className="status-badge unknown-owner" style={{ marginBottom: '0.25rem' }}>Owner Unknown</span>
                )}

                <span>{subtitle ? subtitle : (c.ownerInfo?.name || 'No Owner Listed')}</span>

                <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '0.25rem', fontSize: '0.75rem', color: 'var(--text-light)' }}>
                    <span>#{c.caseId}</span>
                    <span>{expiryDateText}</span>
                </div>
            </div>
        </div>
    );
};

const CaseList: React.FC<CaseListProps> = ({ cases, onSelectCase, onNewCase, listType = 'all', onGenerateReport }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [filter, setFilter] = useState('ALL');

    const filterOptions = [
        { value: 'ALL', label: 'All Open & Closed Cases' },
        { value: 'OPEN', label: 'All Open Cases' },
        { value: 'ABATEMENT', label: 'Ready for Abatement' },
        { value: 'VACANT', label: 'Vacant Properties' },
        { value: 'DILAPIDATED', label: 'Dilapidated Structures' },
        { value: 'UNKNOWN_OWNER', label: 'Unknown Owner' },
        { value: 'TALL_GRASS', label: 'Tall Grass / Weeds' },
        { value: 'INOPERABLE_VEHICLE', label: 'Inoperable Vehicles' },
    ];

    const filteredCases = useMemo(() => {
        let intermediateCases = [...cases];

        const filterFunctions: Record<string, (c: Case) => boolean> = {
            'OPEN': c => c.status !== 'CLOSED',
            'ABATEMENT': c => c.status === 'PENDING_ABATEMENT',
            'VACANT': c => c.isVacant,
            'DILAPIDATED': c => c.violation.type === 'Dilapidated Structure',
            'UNKNOWN_OWNER': c => c.ownerInfoStatus === 'UNKNOWN',
            'TALL_GRASS': c => c.violation.type === 'Tall Grass / Weeds',
            'INOPERABLE_VEHICLE': c => c.violation.type === 'Inoperable / Abandoned Vehicle'
        };

        if (filter !== 'ALL' && filterFunctions[filter]) {
            intermediateCases = intermediateCases.filter(filterFunctions[filter]);
        }

        const sortedCases = intermediateCases.sort((a, b) => {
            if (listType === 'abatement') {
                const statusOrder: Record<string, number> = { 'NEEDS_ABATEMENT': 0, 'STATEMENT_FILED': 1, 'LIEN_FILED': 2, 'LIEN_CERTIFIED': 3 };
                const statA = a.abatement?.status || 'NEEDS_ABATEMENT';
                const statB = b.abatement?.status || 'NEEDS_ABATEMENT';
                if (statusOrder[statA] !== statusOrder[statB]) return statusOrder[statA] - statusOrder[statB];
                return compareStreets(a.address.street, b.address.street); 
            }
            if (a.status === 'CLOSED' && b.status !== 'CLOSED') return 1;
            if (a.status !== 'CLOSED' && b.status === 'CLOSED') return -1;
            return compareStreets(a.address.street, b.address.street);
        });

        if (!searchTerm) return sortedCases;
        return sortedCases.filter(c => 
            c.address.street.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.caseId.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.ownerInfo.name?.toLowerCase().includes(searchTerm.toLowerCase())
        );
    }, [cases, searchTerm, filter, listType]);

    const getLienWaitStatus = (dateStr?: string): { daysLeft: number, ready: boolean } => {
        if (!dateStr) return { daysLeft: 30, ready: false };
        const start = new Date(dateStr);
        const now = new Date();
        start.setHours(0,0,0,0);
        now.setHours(0,0,0,0);
        const diffTime = now.getTime() - start.getTime();
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
        const daysLeft = 30 - diffDays;
        return { 
            daysLeft: Math.max(0, daysLeft),
            ready: diffDays >= 30 
        };
    };

    const renderAbatementGroups = () => {
        const groups: Record<string, { cases: Case[], info: string, color: string }> = {
            'Needs Abatement': { cases: [], info: 'Work needs to be performed or documented.', color: 'var(--danger-color)' },
            'Statement Filed': { cases: [], info: 'Work done. Waiting to file Lien.', color: 'var(--primary-color)' },
            'Lien Waiting Period': { cases: [], info: 'Notice of Lien filed. Waiting 30 days.', color: 'var(--warning-color)' },
            'Action Required': { cases: [], info: '30-day period expired. Ready for Certificate of Lien.', color: 'var(--abatement-color)' },
            'Finalized': { cases: [], info: 'Lien Certified or Released.', color: 'var(--success-color)' }
        };

        filteredCases.forEach(c => {
            const status = c.abatement?.status || 'NEEDS_ABATEMENT';
            if (status === 'NEEDS_ABATEMENT') {
                groups['Needs Abatement'].cases.push(c);
            } else if (status === 'STATEMENT_FILED') {
                groups['Statement Filed'].cases.push(c);
            } else if (status === 'LIEN_FILED') {
                const { ready } = getLienWaitStatus(c.abatement?.noticeOfLienDate);
                if (ready) {
                    groups['Action Required'].cases.push(c);
                } else {
                    groups['Lien Waiting Period'].cases.push(c);
                }
            } else if (status === 'LIEN_CERTIFIED' || status === 'LIEN_RELEASED') {
                groups['Finalized'].cases.push(c);
            } else {
                groups['Needs Abatement'].cases.push(c);
            }
        });

        return (
            <div className="abatement-groups">
                {Object.entries(groups).map(([groupName, data]) => (
                    <div key={groupName} style={{marginBottom: '2rem'}}>
                        <h3 style={{
                            fontSize: '0.95rem',
                            borderBottom: '2px solid var(--bg-color)', 
                            paddingBottom: '0.5rem',
                            color: data.color,
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center',
                            marginBottom: '1rem',
                            textTransform: 'uppercase',
                            letterSpacing: '0.05em'
                        }}>
                            {groupName} 
                            <span style={{
                                fontSize: '0.8rem', 
                                backgroundColor: data.cases.length > 0 ? data.color : 'var(--border-color)', 
                                color: 'white', 
                                padding: '2px 8px', 
                                borderRadius: '12px'
                            }}>
                                {data.cases.length}
                            </span>
                        </h3>

                        {data.cases.length > 0 ? (
                            data.cases.map(c => {
                                let subtitle = c.ownerInfo?.name || 'Unknown Owner';
                                let badge = undefined;
                                let badgeColor = undefined;

                                if (groupName === 'Lien Waiting Period') {
                                    const { daysLeft } = getLienWaitStatus(c.abatement?.noticeOfLienDate);
                                    badge = `${daysLeft} Days Left`;
                                    badgeColor = 'var(--warning-color)';
                                    subtitle = `Filed: ${c.abatement?.noticeOfLienDate || 'Unknown'}`;
                                } else if (groupName === 'Action Required') {
                                    badge = 'READY TO CERTIFY';
                                    badgeColor = 'var(--success-color)';
                                }

                                return (
                                    <CaseItemRow 
                                        key={c.id} 
                                        c={c} 
                                        onSelect={() => onSelectCase(c.id)} 
                                        showExpiry={listType === 'continual-abatement'}
                                        subtitle={subtitle}
                                        badge={badge}
                                        badgeColor={badgeColor}
                                    />
                                );
                            })
                        ) : (
                            <p style={{color: 'var(--text-light)', fontStyle: 'italic', fontSize: '0.9rem', padding: '0.5rem'}}>No cases.</p>
                        )}
                    </div>
                ))}
            </div>
        );
    };

    return (
        <div className="tab-content">
            <div className="search-bar">
                 <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                <input type="text" placeholder="Search cases..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>

            {listType === 'all' && (
                <div className="form-group" style={{ marginBottom: '1.25rem' }}>
                    <select id="case-filter" value={filter} onChange={e => setFilter(e.target.value)}>
                        {filterOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                    </select>
                </div>
            )}

             {listType === 'abatement' && onGenerateReport && (
                 <button className="button full-width" onClick={onGenerateReport} style={{marginBottom: '1rem', backgroundColor: 'var(--abatement-color)'}}>Generate Abatement Report</button>
            )}

            <button className="button primary-action full-width" onClick={onNewCase} style={{ boxShadow: 'var(--shadow-md)' }}>Create New Case</button>

            <div style={{marginTop: '1.5rem'}}>
                {filteredCases.length > 0 ? (
                    listType === 'abatement' ? (
                        renderAbatementGroups()
                    ) : (
                        filteredCases.map(c => (
                            <CaseItemRow 
                                key={c.id} 
                                c={c} 
                                onSelect={() => onSelectCase(c.id)} 
                                showExpiry={listType === 'continual-abatement'} 
                            />
                        ))
                    )
                ) : ( <div className="card empty-state"><p style={{textAlign: 'center', color: 'var(--text-light)'}}>No cases found matching your criteria.</p></div> )}
            </div>
        </div>
    );
};

export default CaseList;

:root {
  /* Calm & Friendly Palette */
  --primary-color: #0284c7; /* Sky 600 - Friendly Blue */
  --primary-dark: #0369a1;  /* Sky 700 */
  --primary-light: #e0f2fe; /* Sky 100 */

  --bg-color: #f3f4f6;      /* Cool Gray 100 - Soft background */
  --card-bg: #ffffff;

  --text-main: #1f2937;     /* Gray 800 - Softer than black */
  --text-secondary: #6b7280; /* Gray 500 */
  --text-light: #9ca3af;    /* Gray 400 */

  --border-color: #e5e7eb;  /* Gray 200 - Subtle borders */

  --danger-color: #ef4444;  /* Red 500 */
  --success-color: #10b981; /* Emerald 500 */
  --warning-color: #f59e0b; /* Amber 500 */
  --abatement-color: #8b5cf6; /* Violet 500 */

  /* Soft Shadows */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -2px rgba(0, 0, 0, 0.025);

  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-full: 9999px;

  --header-height: 64px;
  --font-family: 'Roboto', -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: var(--font-family);
  background-color: var(--bg-color);
  color: var(--text-main);
  line-height: 1.6; /* Increased line height for readability */
  font-size: 16px;  /* Slightly larger base text */
  padding-bottom: 40px;
}

/* --- Header --- */
.app-header {
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(8px);
  height: var(--header-height);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 1.25rem;
  position: sticky;
  top: 0;
  z-index: 100;
  border-bottom: 1px solid var(--border-color);
  box-shadow: var(--shadow-sm);
}

.app-header h1 {
  font-size: 1.25rem;
  font-weight: 700;
  color: var(--text-main);
  text-align: center;
  flex-grow: 1;
}

/* --- Layout --- */
.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

#root {
  max-width: 100%;
}

@media (min-width: 1024px) {
    #root {
        max-width: 800px; /* Constrain width for better reading on desktop */
        margin: 0 auto;
        background: var(--bg-color);
        min-height: 100vh;
        border-left: 1px solid var(--border-color);
        border-right: 1px solid var(--border-color);
    }
}

/* --- Navigation --- */
.main-nav {
  display: flex;
  overflow-x: auto;
  background-color: var(--bg-color);
  padding: 0.75rem 1rem;
  position: sticky;
  top: var(--header-height);
  z-index: 90;
  scrollbar-width: none;
  gap: 0.75rem;
}

.main-nav::-webkit-scrollbar { display: none; }

.main-nav button {
  flex: 0 0 auto;
  padding: 0.5rem 1.25rem;
  border: 1px solid transparent;
  background: var(--card-bg);
  color: var(--text-secondary);
  font-size: 0.95rem;
  font-weight: 500;
  cursor: pointer;
  border-radius: var(--radius-full);
  transition: all 0.2s ease;
  white-space: nowrap;
  box-shadow: var(--shadow-sm);
}

.main-nav button.active {
  background-color: var(--primary-color);
  color: white;
  box-shadow: var(--shadow-md);
  font-weight: 600;
}

/* --- Content Area --- */
.main-content {
  padding: 0.5rem 1rem 2rem 1rem;
  width: 100%;
}

.tab-content {
  display: flex;
  flex-direction: column;
  gap: 1.5rem; /* More space between cards */
  animation: fadeIn 0.4s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

/* --- Cards --- */
.card {
  background-color: var(--card-bg);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  padding: 1.5rem;
  border: 1px solid var(--border-color);
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.card h2 {
  font-size: 1.25rem;
  color: var(--text-main);
  margin-bottom: 1.25rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.card h3 {
  font-size: 1.1rem;
  color: var(--text-main);
  margin-top: 1.5rem;
  margin-bottom: 0.75rem;
  font-weight: 600;
}

/* --- Lists & Items --- */
.case-item {
  background: white;
  padding: 1.25rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  margin-bottom: 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow-sm);
}

.case-item:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
  border-color: var(--primary-light);
}

/* Left colored border for status */
.case-item::before {
    content: '';
    position: absolute;
    left: 0; top: 0; bottom: 0; width: 6px;
    background-color: var(--border-color);
}
.case-item.overdue::before { background-color: var(--warning-color); }
.case-item.abatement::before { background-color: var(--abatement-color); }
.case-item.continual-abatement::before { background-color: var(--abatement-color); }
.case-item.ontime::before { background-color: var(--success-color); }
.case-item.closed { opacity: 0.8; background-color: #fafafa; }
.case-item.new-case::before { background-color: var(--primary-color); }


.case-info strong {
    font-size: 1.1rem;
    color: var(--text-main);
    display: block;
    margin-bottom: 0.2rem;
}
.case-info span {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

/* --- Buttons --- */
.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.5rem;
  border-radius: var(--radius-md);
  border: none;
  background-color: var(--primary-color);
  color: white;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.2s, transform 0.1s;
  min-height: 48px; /* Larger touch target */
  line-height: 1;
  text-decoration: none;
}

.button:hover { background-color: var(--primary-dark); }
.button:active { transform: scale(0.98); }
.button:disabled { background-color: var(--text-light); cursor: not-allowed; opacity: 0.7; }

.button.full-width { width: 100%; }

.button.secondary-action {
  background-color: white;
  color: var(--text-main);
  border: 1px solid var(--border-color);
}
.button.secondary-action:hover { background-color: var(--bg-color); }

.button.danger-action { background-color: var(--danger-color); }
.button.danger-action:hover { background-color: #dc2626; }

.button-group {
  display: flex;
  gap: 1rem;
  margin-top: 1.5rem;
  flex-wrap: wrap;
}

/* --- Forms --- */
.form-group {
  margin-bottom: 1.5rem;
}

.form-group label {
  display: block;
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
}

input[type="text"],
input[type="number"],
input[type="date"],
input[type="tel"],
input[type="email"],
select,
textarea {
  width: 100%;
  padding: 0.75rem 1rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  font-size: 1rem;
  background-color: #fff;
  color: var(--text-main);
  min-height: 50px; /* Taller inputs */
  transition: border-color 0.2s, box-shadow 0.2s;
}

input:focus, select:focus, textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 4px var(--primary-light);
}

.input-with-button {
    display: flex;
    gap: 0.75rem;
}
.input-with-button input { flex-grow: 1; }

/* --- Dashboard Specific --- */
.dashboard-grid {
    display: flex;
    flex-direction: column;
    gap: 1rem;
}

.dashboard-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1.25rem;
    cursor: pointer;
    background: white;
    border-bottom: 1px solid var(--border-color);
}

.dashboard-count-badge {
    background-color: var(--bg-color);
    color: var(--text-main);
    padding: 0.25rem 0.75rem;
    border-radius: var(--radius-full);
    font-size: 0.85rem;
    font-weight: 700;
}

/* --- Timer --- */
.timer-display {
    background: white;
    color: var(--text-main);
    padding: 2rem;
    border-radius: var(--radius-lg);
    text-align: center;
    margin: 1.5rem 0;
    box-shadow: var(--shadow-md);
    border: 2px solid var(--border-color);
}
.timer-count {
    font-size: 4rem;
    font-weight: 800;
    color: var(--primary-color);
    line-height: 1;
}
.timer-label {
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--text-secondary);
    margin-top: 0.5rem;
}
.timer-done .timer-count { color: var(--success-color); }

/* --- Utilities --- */
.helper-text { font-size: 0.9rem; color: var(--text-secondary); margin-top: 0.4rem; }

.status-message, .warning-box, .info-box, .success-message, .error-message {
    padding: 1rem;
    border-radius: var(--radius-md);
    margin: 1rem 0;
    font-size: 0.95rem;
    display: flex;
    align-items: flex-start;
    gap: 0.75rem;
    line-height: 1.5;
}

.success-message { background: #d1fae5; color: #065f46; border: 1px solid #a7f3d0; }
.error-message { background: #fee2e2; color: #991b1b; border: 1px solid #fecaca; }
.warning-box { background: #fef3c7; color: #92400e; border: 1px solid #fde68a; }
.info-box { background: #e0f2fe; color: #075985; border: 1px solid #bae6fd; }

/* Photo Gallery */
.photo-gallery { display: flex; gap: 1rem; overflow-x: auto; padding: 0.5rem 0 1rem 0; }
.photo-thumbnail { 
    width: 100px; height: 100px; flex: 0 0 auto; 
    border-radius: var(--radius-md); overflow: hidden; 
    border: 1px solid var(--border-color); position: relative; 
    box-shadow: var(--shadow-sm);
}
.photo-thumbnail img { width: 100%; height: 100%; object-fit: cover; }

/* Print */
@media print {
    .no-print, .app-header, .main-nav { display: none !important; }
    .app-container { display: block; height: auto; overflow: visible; }
    .card { box-shadow: none; border: 1px solid #000; break-inside: avoid; margin-bottom: 1rem; padding: 0; }
    body { font-size: 12pt; background: white; padding: 0; }
}

import React, { useState, useEffect, useMemo } from 'react';
import { Case } from '../types';
import { STREET_ORDER } from '../utils';
import * as dailyTaskService from '../dailyTaskService';
import { DailyProgress } from '../dailyTaskService';
import { generateCertificateOfMail } from '../googleSheetsService';

interface DailyTasksProps {
    cases: Case[];
    onSelectCase: (caseId: string) => void;
}

const CollapsibleCard: React.FC<{
    title: string;
    count?: number;
    children: React.ReactNode;
    defaultExpanded?: boolean;
    borderColorClass?: string;
}> = ({ title, count, children, defaultExpanded = false, borderColorClass = '' }) => {
    const [expanded, setExpanded] = useState(defaultExpanded);

    // Dynamic border style handling via inline for color logic, but structure via class
    const borderStyle = borderColorClass ? { borderLeft: `5px solid ${borderColorClass}` } : {};

    return (
        <div className="card" style={{ padding: 0, overflow: 'hidden', ...borderStyle }}>
            <div 
                className="dashboard-card-header"
                onClick={() => setExpanded(!expanded)} 
            >
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <h2 style={{ margin: 0, fontSize: '1.1rem', color: 'var(--text-main)' }}>{title}</h2>
                    {count !== undefined && (
                        <span className="dashboard-count-badge" style={{ backgroundColor: count > 0 ? borderColorClass : 'var(--bg-color)', color: count > 0 ? 'white' : 'var(--text-secondary)' }}>
                            {count}
                        </span>
                    )}
                </div>
                <span style={{ fontSize: '1.25rem', color: 'var(--text-light)', transition: 'transform 0.3s', transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)' }}>&#9662;</span>
            </div>
            {expanded && <div style={{ padding: '1.5rem', animation: 'fadeIn 0.3s' }}>{children}</div>}
        </div>
    );
};

const TaskItem: React.FC<{
    title: string;
    subtext?: string;
    onClick: () => void;
    statusClass?: string;
}> = ({ title, subtext, onClick, statusClass }) => (
    <div className={`case-item ${statusClass || ''}`} onClick={onClick} role="button" tabIndex={0}>
        <div className="case-info">
            <strong>{title}</strong>
            {subtext && <span>{subtext}</span>}
        </div>
        <div style={{ position: 'absolute', right: '1.25rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-light)' }}>
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"></polyline></svg>
        </div>
    </div>
);


const DailyTasks: React.FC<DailyTasksProps> = ({ cases, onSelectCase }) => {
    const [patrolIndex, setPatrolIndex] = useState(-1);
    const [todaysProgress, setTodaysProgress] = useState<DailyProgress>({ completedStreets: [], completedCaseTasks: {} });

    const [certQueue, setCertQueue] = useState<string[]>([]);
    const [isGeneratingCert, setIsGeneratingCert] = useState(false);
    const [certError, setCertError] = useState('');
    const [certSuccess, setCertSuccess] = useState('');

    useEffect(() => {
        dailyTaskService.checkAndRotatePatrol();
        setPatrolIndex(dailyTaskService.getPatrolState().lastCompletedIndex);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
        setCertQueue(dailyTaskService.getCertMailQueue());
    }, []);

    useEffect(() => {
        const refreshState = () => {
            const latestProgress = dailyTaskService.getTodaysProgress();
            setTodaysProgress(current => JSON.stringify(latestProgress) !== JSON.stringify(current) ? latestProgress : current);
            const latestQueue = dailyTaskService.getCertMailQueue();
            setCertQueue(current => JSON.stringify(latestQueue) !== JSON.stringify(current) ? latestQueue : current);
            const latestState = dailyTaskService.getPatrolState();
            setPatrolIndex(latestState.lastCompletedIndex);
        };
        window.addEventListener('focus', refreshState);
        return () => window.removeEventListener('focus', refreshState);
    }, []);


    const casesForCert = useMemo(() => {
        return cases.filter(c => certQueue.includes(c.id));
    }, [certQueue, cases]);

    const handleGenerateCertificate = async () => {
        if (casesForCert.length === 0) return;
        setIsGeneratingCert(true);
        setCertError('');
        setCertSuccess('');
        try {
            const generatedDocs = await generateCertificateOfMail(casesForCert);
            generatedDocs.forEach(doc => window.open(doc.docUrl, '_blank'));
            setCertSuccess(`Successfully generated ${generatedDocs.length} certificate document(s).`);
            dailyTaskService.clearCertMailQueue();
            setCertQueue([]);
        } catch (e: any) {
            setCertError(`Failed to generate certificate: ${e.message}`);
        } finally {
            setIsGeneratingCert(false);
        }
    };

    const handleRemoveFromQueue = (caseId: string) => {
        dailyTaskService.removeFromCertMailQueue(caseId);
        setCertQueue(current => current.filter(id => id !== caseId));
    };

    const handleAdvancePatrol = () => {
        dailyTaskService.advancePatrol(STREET_ORDER.length);
        const state = dailyTaskService.getPatrolState();
        state.lastRotationDate = new Date().toISOString().split('T')[0];
        dailyTaskService.savePatrolState(state);
        setPatrolIndex(state.lastCompletedIndex);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
    };

    const handleStreetToggle = (street: string, checked: boolean) => {
        dailyTaskService.markStreetComplete(street, checked);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
    };

    const handleEnvelopeToggle = (caseId: string, isComplete: boolean) => {
        dailyTaskService.setTaskComplete(caseId, 'envelope', isComplete);
        setTodaysProgress(dailyTaskService.getTodaysProgress());
    };

    const now = new Date();
    const sevenDaysAgo = new Date(new Date().setDate(now.getDate() - 7));

    const newCases = cases.filter(c => 
        new Date(c.dateCreated) >= sevenDaysAgo && c.status !== 'CLOSED'
    ).sort((a,b) => new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime());

    const newCaseTasks = newCases.map(c => {
        const progress = todaysProgress.completedCaseTasks[c.id] || [];
        const noticeDone = c.notices.length > 0 || progress.includes('notice');
        const envelopeDone = progress.includes('envelope');
        return { ...c, noticeDone, envelopeDone, isComplete: noticeDone && envelopeDone };
    }).filter(c => !c.isComplete);

    const dueCases = cases.filter(c => {
        const deadline = new Date(c.complianceDeadline);
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        return deadline < today && c.status !== 'CLOSED' && c.status !== 'PENDING_ABATEMENT';
    });

    const abatementCases = cases.filter(c => c.status === 'PENDING_ABATEMENT');
    const currentPatrolIndex = patrolIndex === -1 ? 0 : patrolIndex;
    const streetsForPatrol = STREET_ORDER.slice(currentPatrolIndex, currentPatrolIndex + 3);

    return (
        <div className="tab-content">
            <style>{`
                .task-list { display: flex; flex-direction: column; gap: 0.75rem; }
                .subtask-list { margin-top: 0.75rem; display: flex; flex-direction: column; gap: 0.5rem; }
                .subtask-item { 
                    display: flex; align-items: center; gap: 0.75rem; 
                    font-size: 0.95rem; color: var(--text-secondary);
                    padding: 0.25rem 0;
                }
                .subtask-item input { 
                    width: 1.25rem; height: 1.25rem; accent-color: var(--primary-color);
                    cursor: pointer;
                }
                .patrol-row {
                    display: flex; align-items: center; gap: 1rem;
                    padding: 1rem; border-bottom: 1px solid var(--border-color);
                }
                .patrol-row:last-child { border-bottom: none; }
                .patrol-row input { width: 1.5rem; height: 1.5rem; accent-color: var(--primary-color); cursor: pointer; }
                .patrol-label { flex-grow: 1; font-weight: 500; font-size: 1.05rem; color: var(--text-main); cursor: pointer; }
                .completed-task { text-decoration: line-through; color: var(--text-light); }
                .task-title { font-weight: 600; color: var(--primary-color); cursor: pointer; font-size: 1.1rem; }
            `}</style>

            {/* PATROL */}
            <div className="card">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                    <h2>Daily Patrol</h2>
                    <button className="button secondary-action" onClick={handleAdvancePatrol} style={{ padding: '0.4rem 0.75rem', fontSize: '0.9rem' }}>Skip Zone &rarr;</button>
                </div>
                <div style={{ backgroundColor: 'var(--bg-color)', borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)' }}>
                    {streetsForPatrol.map(street => (
                        <div key={street} className="patrol-row">
                           <input 
                                type="checkbox"
                                id={`street-${street}`}
                                checked={todaysProgress.completedStreets.includes(street)}
                                onChange={e => handleStreetToggle(street, e.target.checked)}
                            />
                            <label htmlFor={`street-${street}`} className={`patrol-label ${todaysProgress.completedStreets.includes(street) ? 'completed-task' : ''}`}>
                                {street.toUpperCase()}
                            </label>
                        </div>
                    ))}
                </div>
            </div>

            {/* NEW CASES */}
            <CollapsibleCard title="New Cases" count={newCaseTasks.length} defaultExpanded={newCaseTasks.length > 0} borderColorClass="var(--primary-color)">
                <div className="task-list">
                    {newCaseTasks.length > 0 ? newCaseTasks.map(c => (
                        <div key={c.id} className="case-item new-case" style={{cursor: 'default'}}>
                            <div style={{flex: 1}}>
                                <div className="task-title" onClick={() => onSelectCase(c.id)}>{c.address.street}</div>
                                <div className="subtask-list">
                                    <label className={`subtask-item ${c.noticeDone ? 'completed-task' : ''}`}>
                                        <input type="checkbox" checked={c.noticeDone} readOnly />
                                        Initial Notice
                                    </label>
                                    <label className={`subtask-item ${c.envelopeDone ? 'completed-task' : ''}`}>
                                        <input
                                            type="checkbox"
                                            checked={c.envelopeDone}
                                            onChange={(e) => handleEnvelopeToggle(c.id, e.target.checked)}
                                        />
                                        Envelope
                                    </label>
                                </div>
                            </div>
                            <div onClick={() => onSelectCase(c.id)} style={{ cursor: 'pointer', padding: '0.5rem', color: 'var(--text-light)' }}>
                                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"></polyline></svg>
                            </div>
                        </div>
                    )) : <p style={{color: 'var(--text-secondary)', fontStyle: 'italic', textAlign: 'center', padding: '1rem'}}>All new cases processed.</p>}
                </div>
            </CollapsibleCard>

            {/* DUE CASES */}
            <CollapsibleCard title="Due for Follow-up" count={dueCases.length} defaultExpanded={dueCases.length > 0} borderColorClass="var(--warning-color)">
                <div className="task-list">
                    {dueCases.length > 0 ? dueCases.map(c => (
                        <TaskItem 
                            key={c.id}
                            title={c.address.street}
                            subtext={`Deadline: ${c.complianceDeadline}`}
                            onClick={() => onSelectCase(c.id)}
                            statusClass="overdue"
                        />
                    )) : <p style={{color: 'var(--text-secondary)', fontStyle: 'italic', textAlign: 'center', padding: '1rem'}}>No cases currently due.</p>}
                </div>
            </CollapsibleCard>

            {/* ABATEMENT */}
            <CollapsibleCard title="Abatement" count={abatementCases.length} defaultExpanded={abatementCases.length > 0} borderColorClass="var(--abatement-color)">
                <div className="task-list">
                    {abatementCases.length > 0 ? abatementCases.map(c => (
                        <TaskItem 
                            key={c.id}
                            title={c.address.street}
                            subtext={c.abatement?.status?.replace('_', ' ') || 'Pending'}
                            onClick={() => onSelectCase(c.id)}
                            statusClass="abatement"
                        />
                    )) : <p style={{color: 'var(--text-secondary)', fontStyle: 'italic', textAlign: 'center', padding: '1rem'}}>No active abatements.</p>}
                </div>
            </CollapsibleCard>

            {/* ADMIN */}
            <CollapsibleCard title="Mailing Queue" count={casesForCert.length} borderColorClass="var(--text-secondary)">
                 <div className="task-list">
                    {casesForCert.length > 0 ? (
                        <>
                            <button className="button full-width" onClick={handleGenerateCertificate} disabled={isGeneratingCert}>
                                {isGeneratingCert ? <span className="loader" /> : `Generate Certificates (${casesForCert.length})`}
                            </button>
                            {certSuccess && <div className="success-message">{certSuccess}</div>}
                            {certError && <div className="error-message">{certError}</div>}
                            <div style={{marginTop: '0.5rem'}}>
                                {casesForCert.map(c => (
                                    <div key={c.id} className="copyable-row" style={{ marginTop: '0.5rem', padding: '0.75rem 1rem' }}>
                                        <span style={{fontSize: '0.95rem'}}>{c.address.street}</span>
                                        <button className="button danger-action" style={{padding: '0.3rem 0.75rem', fontSize: '0.8rem', height: 'auto', minHeight: 'auto'}} onClick={() => handleRemoveFromQueue(c.id)}>Remove</button>
                                    </div>
                                ))}
                            </div>
                        </>
                    ) : (
                        <p className="helper-text" style={{textAlign: 'center', padding: '1rem'}}>Queue empty.</p>
                    )}
                </div>
            </CollapsibleCard>
        </div>
    );
};

export default DailyTasks;

import React, { useState, useMemo } from 'react';
import { Case, AbatementStatus } from '../types';
import { getCaseTimeStatus, compareStreets } from '../utils';

const getStatusClass = (c: Case): string => {
    if (c.status === 'CLOSED') return 'closed';
    if (c.status === 'PENDING_ABATEMENT') return 'abatement';
    if (c.status === 'CONTINUAL_ABATEMENT') return 'continual-abatement';
    return getCaseTimeStatus(c);
};

interface CaseListProps {
    cases: Case[];
    onSelectCase: (caseId: string) => void;
    onNewCase: () => void;
    listType?: 'all' | 'due' | 'abatement' | 'continual-abatement';
    onGenerateReport?: () => void;
}

const CaseItemRow: React.FC<{ c: Case; onSelect: () => void; showExpiry?: boolean; subtitle?: string; badge?: string; badgeClass?: string }> = ({ c, onSelect, showExpiry, subtitle, badge, badgeClass }) => {
    const statusClass = getStatusClass(c);

    let displayStatus = '';
    if (c.status === 'PENDING_ABATEMENT') displayStatus = 'Abatement';
    else if (c.status === 'CONTINUAL_ABATEMENT') displayStatus = 'Continual';
    else if (c.status === 'CLOSED') displayStatus = 'Closed';
    else displayStatus = 'Active';

    let expiryDateText = '';
    if (showExpiry && c.abatement?.workDate) {
        const workDate = new Date(c.abatement.workDate.replace(/-/g, '\/'));
        if (!isNaN(workDate.getTime())) {
            workDate.setMonth(workDate.getMonth() + 6);
            expiryDateText = `Expires: ${workDate.toLocaleDateString()}`;
        }
    }

    return (
        <div className={`case-item ${statusClass}`} onClick={onSelect} role="button" tabIndex={0} aria-label={`View case ${c.caseId}`}>
            <div className="case-info">
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.2rem'}}>
                    <strong>{c.address.street}</strong>
                    {badge ? (
                        <span style={{ 
                            fontSize: '0.75rem', 
                            padding: '2px 8px', 
                            borderRadius: '99px', 
                            fontWeight: 700, 
                            textTransform: 'uppercase',
                            backgroundColor: badgeClass ? `var(${badgeClass})` : 'var(--primary-color)',
                            color: 'white'
                        }}>{badge}</span>
                    ) : (
                        <span style={{ fontSize: '0.8rem', color: 'var(--text-light)', fontWeight: 600 }}>{displayStatus.toUpperCase()}</span>
                    )}
                </div>

                {c.ownerInfoStatus === 'UNKNOWN' && (
                     <span style={{ fontSize: '0.75rem', backgroundColor: '#fef08a', color: '#854d0e', padding: '2px 6px', borderRadius: '4px', fontWeight: 600, display: 'inline-block', marginBottom: '0.25rem' }}>Owner Unknown</span>
                )}

                <span>{subtitle ? subtitle : (c.ownerInfo?.name || 'No Owner Listed')}</span>

                <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '0.5rem', fontSize: '0.85rem', color: 'var(--text-light)' }}>
                    <span>#{c.caseId}</span>
                    <span>{expiryDateText}</span>
                </div>
            </div>
        </div>
    );
};

const CaseList: React.FC<CaseListProps> = ({ cases, onSelectCase, onNewCase, listType = 'all', onGenerateReport }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [filter, setFilter] = useState('ALL');

    const filterOptions = [
        { value: 'ALL', label: 'All Open & Closed Cases' },
        { value: 'OPEN', label: 'All Open Cases' },
        { value: 'ABATEMENT', label: 'Ready for Abatement' },
        { value: 'VACANT', label: 'Vacant Properties' },
        { value: 'DILAPIDATED', label: 'Dilapidated Structures' },
        { value: 'UNKNOWN_OWNER', label: 'Unknown Owner' },
        { value: 'TALL_GRASS', label: 'Tall Grass / Weeds' },
        { value: 'INOPERABLE_VEHICLE', label: 'Inoperable Vehicles' },
    ];

    const filteredCases = useMemo(() => {
        let intermediateCases = [...cases];

        const filterFunctions: Record<string, (c: Case) => boolean> = {
            'OPEN': c => c.status !== 'CLOSED',
            'ABATEMENT': c => c.status === 'PENDING_ABATEMENT',
            'VACANT': c => c.isVacant,
            'DILAPIDATED': c => c.violation.type === 'Dilapidated Structure',
            'UNKNOWN_OWNER': c => c.ownerInfoStatus === 'UNKNOWN',
            'TALL_GRASS': c => c.violation.type === 'Tall Grass / Weeds',
            'INOPERABLE_VEHICLE': c => c.violation.type === 'Inoperable / Abandoned Vehicle'
        };

        if (filter !== 'ALL' && filterFunctions[filter]) {
            intermediateCases = intermediateCases.filter(filterFunctions[filter]);
        }

        const sortedCases = intermediateCases.sort((a, b) => {
            if (listType === 'abatement') {
                const statusOrder: Record<string, number> = { 'NEEDS_ABATEMENT': 0, 'STATEMENT_FILED': 1, 'LIEN_FILED': 2, 'LIEN_CERTIFIED': 3 };
                const statA = a.abatement?.status || 'NEEDS_ABATEMENT';
                const statB = b.abatement?.status || 'NEEDS_ABATEMENT';
                if (statusOrder[statA] !== statusOrder[statB]) return statusOrder[statA] - statusOrder[statB];
                return compareStreets(a.address.street, b.address.street); 
            }
            if (a.status === 'CLOSED' && b.status !== 'CLOSED') return 1;
            if (a.status !== 'CLOSED' && b.status === 'CLOSED') return -1;
            return compareStreets(a.address.street, b.address.street);
        });

        if (!searchTerm) return sortedCases;
        return sortedCases.filter(c => 
            c.address.street.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.caseId.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.ownerInfo.name?.toLowerCase().includes(searchTerm.toLowerCase())
        );
    }, [cases, searchTerm, filter, listType]);

    const getLienWaitStatus = (dateStr?: string): { daysLeft: number, ready: boolean } => {
        if (!dateStr) return { daysLeft: 30, ready: false };
        const start = new Date(dateStr);
        const now = new Date();
        start.setHours(0,0,0,0);
        now.setHours(0,0,0,0);
        const diffTime = now.getTime() - start.getTime();
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
        const daysLeft = 30 - diffDays;
        return { 
            daysLeft: Math.max(0, daysLeft),
            ready: diffDays >= 30 
        };
    };

    const renderAbatementGroups = () => {
        const groups: Record<string, { cases: Case[], info: string, colorClass: string }> = {
            'Needs Abatement': { cases: [], info: 'Work needs to be performed or documented.', colorClass: '--danger-color' },
            'Statement Filed': { cases: [], info: 'Work done. Waiting to file Lien.', colorClass: '--primary-color' },
            'Lien Waiting Period': { cases: [], info: 'Notice of Lien filed. Waiting 30 days.', colorClass: '--warning-color' },
            'Action Required': { cases: [], info: '30-day period expired. Ready for Certificate of Lien.', colorClass: '--abatement-color' },
            'Finalized': { cases: [], info: 'Lien Certified or Released.', colorClass: '--success-color' }
        };

        filteredCases.forEach(c => {
            const status = c.abatement?.status || 'NEEDS_ABATEMENT';
            if (status === 'NEEDS_ABATEMENT') {
                groups['Needs Abatement'].cases.push(c);
            } else if (status === 'STATEMENT_FILED') {
                groups['Statement Filed'].cases.push(c);
            } else if (status === 'LIEN_FILED') {
                const { ready } = getLienWaitStatus(c.abatement?.noticeOfLienDate);
                if (ready) {
                    groups['Action Required'].cases.push(c);
                } else {
                    groups['Lien Waiting Period'].cases.push(c);
                }
            } else if (status === 'LIEN_CERTIFIED' || status === 'LIEN_RELEASED') {
                groups['Finalized'].cases.push(c);
            } else {
                groups['Needs Abatement'].cases.push(c);
            }
        });

        return (
            <div className="abatement-groups">
                {Object.entries(groups).map(([groupName, data]) => (
                    <div key={groupName} style={{marginBottom: '2rem'}}>
                        <h3 style={{
                            fontSize: '1rem',
                            borderBottom: '2px solid var(--border-color)', 
                            paddingBottom: '0.5rem',
                            color: `var(${data.colorClass})`,
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center',
                            marginBottom: '1rem',
                            textTransform: 'uppercase',
                            letterSpacing: '0.05em'
                        }}>
                            {groupName} 
                            <span style={{
                                fontSize: '0.85rem', 
                                backgroundColor: data.cases.length > 0 ? `var(${data.colorClass})` : 'var(--bg-color)', 
                                color: data.cases.length > 0 ? 'white' : 'var(--text-secondary)', 
                                padding: '2px 10px', 
                                borderRadius: '99px'
                            }}>
                                {data.cases.length}
                            </span>
                        </h3>

                        {data.cases.length > 0 ? (
                            data.cases.map(c => {
                                let subtitle = c.ownerInfo?.name || 'Unknown Owner';
                                let badge = undefined;
                                let badgeClass = undefined;

                                if (groupName === 'Lien Waiting Period') {
                                    const { daysLeft } = getLienWaitStatus(c.abatement?.noticeOfLienDate);
                                    badge = `${daysLeft} Days Left`;
                                    badgeClass = '--warning-color';
                                    subtitle = `Filed: ${c.abatement?.noticeOfLienDate || 'Unknown'}`;
                                } else if (groupName === 'Action Required') {
                                    badge = 'READY TO CERTIFY';
                                    badgeClass = '--success-color';
                                }

                                return (
                                    <CaseItemRow 
                                        key={c.id} 
                                        c={c} 
                                        onSelect={() => onSelectCase(c.id)} 
                                        showExpiry={listType === 'continual-abatement'}
                                        subtitle={subtitle}
                                        badge={badge}
                                        badgeClass={badgeClass}
                                    />
                                );
                            })
                        ) : (
                            <p style={{color: 'var(--text-secondary)', fontStyle: 'italic', fontSize: '0.95rem', padding: '0.5rem'}}>No cases in this stage.</p>
                        )}
                    </div>
                ))}
            </div>
        );
    };

    return (
        <div className="tab-content">
            <div className="search-bar">
                 <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                <input type="text" placeholder="Search cases..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>

            {listType === 'all' && (
                <div className="form-group" style={{ marginBottom: '1.25rem' }}>
                    <select id="case-filter" value={filter} onChange={e => setFilter(e.target.value)}>
                        {filterOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                    </select>
                </div>
            )}

             {listType === 'abatement' && onGenerateReport && (
                 <button className="button full-width" onClick={onGenerateReport} style={{marginBottom: '1rem', backgroundColor: 'var(--abatement-color)'}}>Generate Abatement Report</button>
            )}

            <button className="button primary-action full-width" onClick={onNewCase} style={{ boxShadow: 'var(--shadow-md)' }}>Create New Case</button>

            <div style={{marginTop: '2rem'}}>
                {filteredCases.length > 0 ? (
                    listType === 'abatement' ? (
                        renderAbatementGroups()
                    ) : (
                        filteredCases.map(c => (
                            <CaseItemRow 
                                key={c.id} 
                                c={c} 
                                onSelect={() => onSelectCase(c.id)} 
                                showExpiry={listType === 'continual-abatement'} 
                            />
                        ))
                    )
                ) : ( <div className="card empty-state"><p style={{textAlign: 'center', color: 'var(--text-secondary)'}}>No cases found matching your criteria.</p></div> )}
            </div>
        </div>
    );
};

