:root {
  /* Calm & Friendly Palette */
  --primary-color: #0284c7; /* Sky 600 - Friendly Blue */
  --primary-dark: #0369a1;  /* Sky 700 */
  --primary-light: #e0f2fe; /* Sky 100 */

  --bg-color: #f3f4f6;      /* Cool Gray 100 - Soft background */
  --card-bg: #ffffff;

  --text-main: #1f2937;     /* Gray 800 - Softer than black */
  --text-secondary: #6b7280; /* Gray 500 */
  --text-light: #9ca3af;    /* Gray 400 */

  --border-color: #e5e7eb;  /* Gray 200 - Subtle borders */

  --danger-color: #ef4444;  /* Red 500 */
  --success-color: #10b981; /* Emerald 500 */
  --warning-color: #f59e0b; /* Amber 500 */
  --abatement-color: #8b5cf6; /* Violet 500 */

  /* Soft Shadows */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -2px rgba(0, 0, 0, 0.025);

  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-full: 9999px;

  --header-height: 64px;
  --font-family: 'Roboto', -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: var(--font-family);
  background-color: var(--bg-color);
  color: var(--text-main);
  line-height: 1.6; /* Increased line height for readability */
  font-size: 16px;  /* Slightly larger base text */
  padding-bottom: 40px;
  overflow-x: hidden; /* Prevent horizontal scroll on body */
}

/* --- Header --- */
.app-header {
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(8px);
  height: var(--header-height);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 1.25rem;
  position: sticky;
  top: 0;
  z-index: 100;
  border-bottom: 1px solid var(--border-color);
  box-shadow: var(--shadow-sm);
}

.app-header h1 {
  font-size: 1.25rem;
  font-weight: 700;
  color: var(--text-main);
  text-align: center;
  flex-grow: 1;
}

/* --- Layout --- */
.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

#root {
  max-width: 100%;
}

@media (min-width: 1024px) {
    #root {
        max-width: 800px; /* Constrain width for better reading on desktop */
        margin: 0 auto;
        background: var(--bg-color);
        min-height: 100vh;
        border-left: 1px solid var(--border-color);
        border-right: 1px solid var(--border-color);
    }
}

/* --- Navigation --- */
.main-nav {
  display: flex;
  flex-wrap: wrap; /* Wrap items to prevent overflow */
  justify-content: center; /* Center items for balanced look */
  background-color: var(--bg-color);
  padding: 0.75rem 1rem;
  position: sticky;
  top: var(--header-height);
  z-index: 90;
  gap: 0.5rem;
  border-bottom: 1px solid transparent; /* Placeholder for potential border */
}

.main-nav button {
  flex: 0 0 auto;
  padding: 0.5rem 1rem;
  border: 1px solid transparent;
  background: var(--card-bg);
  color: var(--text-secondary);
  font-size: 0.9rem;
  font-weight: 500;
  cursor: pointer;
  border-radius: var(--radius-full);
  transition: all 0.2s ease;
  white-space: nowrap;
  box-shadow: var(--shadow-sm);
}

.main-nav button.active {
  background-color: var(--primary-color);
  color: white;
  box-shadow: var(--shadow-md);
  font-weight: 600;
}

/* --- Content Area --- */
.main-content {
  padding: 0.5rem 1rem 2rem 1rem;
  width: 100%;
}

.tab-content {
  display: flex;
  flex-direction: column;
  gap: 1.5rem; /* More space between cards */
  animation: fadeIn 0.4s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

/* --- Cards --- */
.card {
  background-color: var(--card-bg);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  padding: 1.5rem;
  border: 1px solid var(--border-color);
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.card h2 {
  font-size: 1.25rem;
  color: var(--text-main);
  margin-bottom: 1.25rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.card h3 {
  font-size: 1.1rem;
  color: var(--text-main);
  margin-top: 1.5rem;
  margin-bottom: 0.75rem;
  font-weight: 600;
}

/* --- Lists & Items --- */
.case-item {
  background: white;
  padding: 1.25rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  margin-bottom: 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow-sm);
}

.case-item:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
  border-color: var(--primary-light);
}

/* Left colored border for status */
.case-item::before {
    content: '';
    position: absolute;
    left: 0; top: 0; bottom: 0; width: 6px;
    background-color: var(--border-color);
}
.case-item.overdue::before { background-color: var(--warning-color); }
.case-item.abatement::before { background-color: var(--abatement-color); }
.case-item.continual-abatement::before { background-color: var(--abatement-color); }
.case-item.ontime::before { background-color: var(--success-color); }
.case-item.closed { opacity: 0.8; background-color: #fafafa; }
.case-item.new-case::before { background-color: var(--primary-color); }


.case-info strong {
    font-size: 1.1rem;
    color: var(--text-main);
    display: block;
    margin-bottom: 0.2rem;
}
.case-info span {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

/* --- Buttons --- */
.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.5rem;
  border-radius: var(--radius-md);
  border: none;
  background-color: var(--primary-color);
  color: white;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.2s, transform 0.1s;
  min-height: 48px; /* Larger touch target */
  line-height: 1;
  text-decoration: none;
}

.button:hover { background-color: var(--primary-dark); }
.button:active { transform: scale(0.98); }
.button:disabled { background-color: var(--text-light); cursor: not-allowed; opacity: 0.7; }

.button.full-width { width: 100%; }

.button.secondary-action {
  background-color: white;
  color: var(--text-main);
  border: 1px solid var(--border-color);
}
.button.secondary-action:hover { background-color: var(--bg-color); }

.button.danger-action { background-color: var(--danger-color); }
.button.danger-action:hover { background-color: #dc2626; }

.button-group {
  display: flex;
  gap: 1rem;
  margin-top: 1.5rem;
  flex-wrap: wrap;
}

/* --- Forms --- */
.form-group {
  margin-bottom: 1.5rem;
}

.form-group label {
  display: block;
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
}

input[type="text"],
input[type="number"],
input[type="date"],
input[type="tel"],
input[type="email"],
select,
textarea {
  width: 100%;
  padding: 0.75rem 1rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  font-size: 1rem;
  background-color: #fff;
  color: var(--text-main);
  min-height: 50px; /* Taller inputs */
  transition: border-color 0.2s, box-shadow 0.2s;
}

input:focus, select:focus, textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 4px var(--primary-light);
}

.input-with-button {
    display: flex;
    gap: 0.75rem;
}
.input-with-button input { flex-grow: 1; }

/* --- Dashboard Specific --- */
.dashboard-grid {
    display: flex;
    flex-direction: column;
    gap: 1rem;
}

.dashboard-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1.25rem;
    cursor: pointer;
    background: white;
    border-bottom: 1px solid var(--border-color);
}

.dashboard-count-badge {
    background-color: var(--bg-color);
    color: var(--text-main);
    padding: 0.25rem 0.75rem;
    border-radius: var(--radius-full);
    font-size: 0.85rem;
    font-weight: 700;
}

/* --- Timer --- */
.timer-display {
    background: white;
    color: var(--text-main);
    padding: 2rem;
    border-radius: var(--radius-lg);
    text-align: center;
    margin: 1.5rem 0;
    box-shadow: var(--shadow-md);
    border: 2px solid var(--border-color);
}
.timer-count {
    font-size: 4rem;
    font-weight: 800;
    color: var(--primary-color);
    line-height: 1;
}
.timer-label {
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--text-secondary);
    margin-top: 0.5rem;
}
.timer-done .timer-count { color: var(--success-color); }

/* --- Utilities --- */
.helper-text { font-size: 0.9rem; color: var(--text-secondary); margin-top: 0.4rem; }

.status-message, .warning-box, .info-box, .success-message, .error-message {
    padding: 1rem;
    border-radius: var(--radius-md);
    margin: 1rem 0;
    font-size: 0.95rem;
    display: flex;
    align-items: flex-start;
    gap: 0.75rem;
    line-height: 1.5;
}

.success-message { background: #d1fae5; color: #065f46; border: 1px solid #a7f3d0; }
.error-message { background: #fee2e2; color: #991b1b; border: 1px solid #fecaca; }
.warning-box { background: #fef3c7; color: #92400e; border: 1px solid #fde68a; }
.info-box { background: #e0f2fe; color: #075985; border: 1px solid #bae6fd; }

/* Photo Gallery */
.photo-gallery { display: flex; gap: 1rem; overflow-x: auto; padding: 0.5rem 0 1rem 0; }
.photo-thumbnail { 
    width: 100px; height: 100px; flex: 0 0 auto; 
    border-radius: var(--radius-md); overflow: hidden; 
    border: 1px solid var(--border-color); position: relative; 
    box-shadow: var(--shadow-sm);
}
.photo-thumbnail img { width: 100%; height: 100%; object-fit: cover; }

/* Print */
@media print {
    .no-print, .app-header, .main-nav { display: none !important; }
    .app-container { display: block; height: auto; overflow: visible; }
    .card { box-shadow: none; border: 1px solid #000; break-inside: avoid; margin-bottom: 1rem; padding: 0; }
    body { font-size: 12pt; background: white; padding: 0; }
}

