    const ENVELOPE_PLACEHOLDERS = [ "OWNER_NAME", "MAILING_ADDRESS" ];

    const ABATEMENT_COST_PLACEHOLDERS = [
        "LEGAL_DESCRIPTION", "ABATEMENT_WORK_DATE", "ABATEMENT_HOURS", "ABATEMENT_EMPLOYEES", "ABATEMENT_RATE",
