import React, { useState, useEffect, useRef } from 'react';
import { Case, NoticePurpose, PhotoWithMeta, EvidencePhoto, FollowUp } from '../types';
import { generateNoticeDocument, generateEnvelopeDocument } from '../googleSheetsService';
import { GOOGLE_API_LIBRARY_URL, COMPLIANCE_DAYS, COMMON_NOTES, FOLLOW_UP_NOTES } from '../constants';
import { getCaseTimeStatus } from '../utils';
import { dataService } from '../googleSheetsService';
import { markTaskComplete, addToCertMailQueue, getCertMailQueue, removeFromCertMailQueue } from '../dailyTaskService';
import AbatementManager from './AbatementManager';
import CameraView from './CameraView';
import QuickInput from './QuickInput';

const CaseDetails: React.FC<{ caseData: Case; onBack: () => void; onUpdate: (updatedCase: Case) => void; onDelete: (caseId: string) => void; }> = ({ caseData, onBack, onUpdate, onDelete }) => {
    const [currentCase, setCurrentCase] = useState(caseData);
    const [ownerInfoEdit, setOwnerInfoEdit] = useState(caseData.ownerInfo);
    const [newNote, setNewNote] = useState('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [generationError, setGenerationError] = useState('');
    const [generationMessage, setGenerationMessage] = useState('');
    const [isEditingAddress, setIsEditingAddress] = useState(false);
    const [addressEdit, setAddressEdit] = useState(caseData.address);
    const [isGeneratingEnvelope, setIsGeneratingEnvelope] = useState(false);
    const [isEditingOwnerInfo, setIsEditingOwnerInfo] = useState(false);
    const [isEditingDates, setIsEditingDates] = useState(false);
    const [datesEdit, setDatesEdit] = useState({ dateCreated: '', complianceDeadline: '' });

    const [isArchiving, setIsArchiving] = useState(false);

    const [followUpNotes, setFollowUpNotes] = useState('');
    const [followUpPhotos, setFollowUpPhotos] = useState<PhotoWithMeta[]>([]);
    const [showFollowUpCamera, setShowFollowUpCamera] = useState(false);
    const [isSavingFollowUp, setIsSavingFollowUp] = useState(false);
    const [followUpError, setFollowUpError] = useState('');
    const [extensionDays, setExtensionDays] = useState('7');
    const [isInQueue, setIsInQueue] = useState(false);

    useEffect(() => {
        const queue = getCertMailQueue();
        setIsInQueue(queue.includes(currentCase.id));
    }, [currentCase.id]);

    const handleToggleQueue = () => {
        if (isInQueue) {
            removeFromCertMailQueue(currentCase.id);
            setIsInQueue(false);
        } else {
            addToCertMailQueue(currentCase.id);
            setIsInQueue(true);
        }
    };

    const handleDownloadArchive = async () => {
        if (!window.confirm("This will download all photos, notices (as PDFs), and a case report into a single ZIP file. This may take a moment depending on the number of photos. Continue?")) return;
        setIsArchiving(true);
        try {
            await dataService.downloadCaseArchive(currentCase);
        } catch (e: any) {
            alert(`Failed to download archive: ${e.message}`);
        } finally {
            setIsArchiving(false);
        }
    };

    const isCaseOverdue = getCaseTimeStatus(currentCase) === 'overdue' && currentCase.status !== 'CLOSED' && currentCase.status !== 'PENDING_ABATEMENT';

    const toInputDate = (longDate: string): string => {
        if (!longDate) return '';
        try {
            const d = new Date(longDate);
            if (isNaN(d.getTime())) return '';
            return d.toISOString().split('T')[0];
        } catch {
            return '';
        }
    };

    const fromInputDate = (inputDate: string): string => {
        if (!inputDate) return '';
        try {
            const d = new Date(inputDate.replace(/-/g, '\/'));
            if (isNaN(d.getTime())) return '';
            return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        } catch {
            return '';
        }
    };

    const handleSaveFollowUp = async (action: 'RESOLVE' | 'ABATEMENT') => {
        if (!followUpNotes.trim() && followUpPhotos.length === 0) {
            setFollowUpError("Please add notes or photos for the follow-up.");
            return;
        }
        setIsSavingFollowUp(true);
        setFollowUpError('');
        try {
            const uploadedPhotos = await dataService.uploadCasePhotos(followUpPhotos, currentCase.caseId);
            const today = new Date().toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

            const newFollowUp: FollowUp = {
                date: today,
                notes: followUpNotes.trim(),
                photos: uploadedPhotos,
            };

            const updatedCase = { ...currentCase };
            updatedCase.followUps = [...(currentCase.followUps || []), newFollowUp];
            updatedCase.status = action === 'RESOLVE' ? 'CLOSED' : 'PENDING_ABATEMENT';

            const noteText = action === 'RESOLVE' 
                ? 'Follow-up complete: Violation resolved. Case closed.' 
                : 'Follow-up complete: Violation not resolved. Forwarded for abatement.';
            updatedCase.evidence.notes.unshift({ date: today, text: noteText });

            await onUpdate(updatedCase);
            setCurrentCase(updatedCase);

            setFollowUpNotes('');
            setFollowUpPhotos([]);

        } catch (err: any) {
            setFollowUpError(`Failed to save follow-up: ${err.message}`);
        } finally {
            setIsSavingFollowUp(false);
        }
    };

    const handleSaveOwnerInfo = () => {
        if (!ownerInfoEdit.name || !ownerInfoEdit.mailingAddress) { alert("Owner name and mailing address are required."); return; }
        const wasUnknown = currentCase.ownerInfoStatus === 'UNKNOWN';
        const updatedCase = { ...currentCase, ownerInfo: ownerInfoEdit, ownerInfoStatus: 'KNOWN' as const };
        const today = new Date().toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        const note = { date: today, text: wasUnknown ? "Owner information added." : "Owner information updated." };
        updatedCase.evidence.notes.unshift(note);
        setCurrentCase(updatedCase);
        onUpdate(updatedCase);
        setIsEditingOwnerInfo(false);
    };

    const handleCancelEditOwnerInfo = () => {
        setOwnerInfoEdit(currentCase.ownerInfo);
        setIsEditingOwnerInfo(false);
    };

    const handleSaveAddress = () => {
        if (!addressEdit.street.trim()) {
            alert("Street address cannot be empty.");
            return;
        }
        const today = new Date().toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        const noteText = currentCase.address.street !== addressEdit.street 
            ? `Property address updated from "${currentCase.address.street}" to "${addressEdit.street}".`
            : "Property address details updated.";

        const note = { date: today, text: noteText };

        const updatedCase = {
            ...currentCase,
            address: addressEdit,
            evidence: {
                ...currentCase.evidence,
                notes: [note, ...currentCase.evidence.notes]
            }
        };

        setCurrentCase(updatedCase);
        onUpdate(updatedCase);
        setIsEditingAddress(false);
    };

    const handleCancelEditAddress = () => {
        setAddressEdit(currentCase.address);
        setIsEditingAddress(false);
    };

    const handleEditDates = () => {
        setDatesEdit({
            dateCreated: toInputDate(currentCase.dateCreated),
            complianceDeadline: toInputDate(currentCase.complianceDeadline),
        });
        setIsEditingDates(true);
    };

    const handleSaveDates = () => {
        const newDateCreated = fromInputDate(datesEdit.dateCreated);
        const newComplianceDeadline = fromInputDate(datesEdit.complianceDeadline);

        if (!newDateCreated || !newComplianceDeadline) {
            alert("Please provide valid dates for both fields.");
            return;
        }

        const hasDateCreatedChanged = newDateCreated !== currentCase.dateCreated;
        const hasDeadlineChanged = newComplianceDeadline !== currentCase.complianceDeadline;

        if (!hasDateCreatedChanged && !hasDeadlineChanged) {
            setIsEditingDates(false); // No changes, just close the editor
            return;
        }

        const updatedCase = { ...currentCase };
        const notesToAdd = [];
        const today = new Date().toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

        if (hasDateCreatedChanged) {
            updatedCase.dateCreated = newDateCreated;
            notesToAdd.push({ date: today, text: `Case creation date updated from "${currentCase.dateCreated}" to "${newDateCreated}".` });
        }
        if (hasDeadlineChanged) {
            updatedCase.complianceDeadline = newComplianceDeadline;
            notesToAdd.push({ date: today, text: `Compliance deadline updated from "${currentCase.complianceDeadline}" to "${newComplianceDeadline}".` });
        }

        updatedCase.evidence.notes.unshift(...notesToAdd);
        setCurrentCase(updatedCase);
        onUpdate(updatedCase);
        setIsEditingDates(false);
    };

    const handleCancelEditDates = () => {
        setIsEditingDates(false);
    };


    const handleAddNote = () => {
        if (!newNote.trim()) return;
        const today = new Date().toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        const note = { date: today, text: newNote.trim() };
        const updatedCase = { ...currentCase, evidence: { ...currentCase.evidence, notes: [note, ...currentCase.evidence.notes] } };
        setCurrentCase(updatedCase);
        onUpdate(updatedCase);
        setNewNote('');
    };

    const handleGenerateEnvelope = async () => {
        if (!currentCase.ownerInfo.mailingAddress) {
            alert("No mailing address available for this case.");
            return;
        }
        setIsGeneratingEnvelope(true);
        setGenerationError(''); // Clear previous errors
        try {
            const { docUrl } = await generateEnvelopeDocument(currentCase);
            markTaskComplete(currentCase.id, 'envelope');
            window.open(docUrl, '_blank');
        } catch (e: any) {
            setGenerationError(`Error generating envelope: ${e.message}`);
        } finally {
            setIsGeneratingEnvelope(false);
        }
    };

    const handleGenerateNotice = async (purpose: NoticePurpose) => {
        const purposeLabels: Record<NoticePurpose, string> = {
            'INITIAL': 'Initial Notice',
            'FAILURE': 'Failure to Comply',
            'DILAPIDATED': 'Dilapidated Structure Notice',
            'BOARDING': 'Board & Secure Notice'
        };
        const label = purposeLabels[purpose];

        if (!window.confirm(`Generate "${label}"? This will create a Google Doc in Drive and link it to this case. Continue?`)) return;

        setIsGenerating(true);
        setGenerationError('');
        setGenerationMessage('');
        try {
            const generatedDocs = await generateNoticeDocument(purpose, currentCase);

            if (!generatedDocs || generatedDocs.length === 0) {
                throw new Error("Notice generation failed to return any documents.");
            }

            const primaryNotice = generatedDocs[0]; // Owner notice is always first

            const today = new Date();
            const formattedToday = today.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

            const newDeadline = new Date();
            newDeadline.setDate(today.getDate() + COMPLIANCE_DAYS);
            const formattedNewDeadline = newDeadline.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

            const newNotice = { title: primaryNotice.title, docUrl: primaryNotice.docUrl, date: formattedToday };

            let updatedCase = { ...currentCase };
            updatedCase.complianceDeadline = formattedNewDeadline; // Update deadline on generation
            updatedCase.notices.unshift(newNotice);
            updatedCase.evidence.notes.unshift({ date: formattedToday, text: `Generated notice: "${primaryNotice.title}"` });
            updatedCase.evidence.notes.unshift({ date: formattedToday, text: `Compliance deadline reset to ${formattedNewDeadline}.` });

            if (purpose === 'FAILURE') { 
                updatedCase.status = 'FAILURE-NOTICED'; 
            }

            setCurrentCase(updatedCase);
            onUpdate(updatedCase);

            if (purpose === 'INITIAL') {
                markTaskComplete(currentCase.id, 'notice');
            }

            generatedDocs.forEach(doc => {
                window.open(doc.docUrl, '_blank');
            });

            const docTypes = generatedDocs.map(d => d.title.includes('Owner') ? 'Owner' : d.title.includes('Occupant') ? 'Occupant' : 'Posting').join(', ');
            setGenerationMessage(`Successfully generated ${generatedDocs.length} notice(s): ${docTypes}. They should open in new tabs.`);

        } catch (e: any) { 
            console.error(e);
            let detailedError = e.message;
            if (typeof e.message === 'string') {
                 if (e.message.includes('SERVICE_DISABLED') || e.message.includes('docs.googleapis.com')) {
                    detailedError = "**Google Docs API Not Enabled**\n\n" +
                                   "To generate notices, the Google Docs API must be enabled in your Google Cloud Project.\n\n" +
                                   `1. **[Click here to go to the API Library](${GOOGLE_API_LIBRARY_URL})**\n` +
                                   "2. Search for \"Google Docs API\" and enable it.\n" +
                                   "3. Wait a few minutes, then try generating the notice again.\n\n" +
                                   `Raw Error: ${e.message}`;
                 } else if (e.message.includes('appNotAuthorizedToFile') || e.message.includes('403') || e.message.includes('permission') || e.message.includes('File not found')) {
                     detailedError = "The app was denied permission to access your Google Doc template.\n\n" +
                                    "This is usually a configuration issue. Please take the following steps:\n\n" +
                                    "1. **Check Sharing:** Open the Google Doc template and share it with the Google account you are using for this app (give at least 'Viewer' access).\n\n" +
                                    "2. **Re-authorize App:** Go to the 'Admin' tab, click 'Clear All Settings', and then sign in again. This forces the app to request the correct permissions from Google.\n\n" +
                                    `If the issue persists, the raw error from Google was: ${e.message}`;
                } else if (e.message.includes('Invalid Google Doc URL')) {
                    detailedError = `The template URL is invalid. Please go to the Templates tab and check that the URL is a valid Google Doc link.`;
                } else if (e.message.includes('No template URL configured')) {
                    detailedError = `The template URL is missing. Please go to the 'Templates' tab and provide the URL for "${purpose}" notices.`;
                }
            }
            setGenerationError(`Error generating notice: ${detailedError}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleResolveCase = () => {
        if (!window.confirm("Are you sure you want to mark this case as resolved? This will close the case.")) return;

        const today = new Date().toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        const note = { date: today, text: "Violation resolved. Case closed." };

        const updatedCase = {
            ...currentCase,
            status: 'CLOSED' as const,
            evidence: {
                ...currentCase.evidence,
                notes: [note, ...currentCase.evidence.notes]
            }
        };

        setCurrentCase(updatedCase);
        onUpdate(updatedCase);
    };

    const handleGrantExtension = () => {
        const days = parseInt(extensionDays, 10);
        if (isNaN(days) || days <= 0) {
            alert("Please enter a valid number of days for the extension.");
            return;
        }

        if (currentCase.status === 'CLOSED') {
            alert("Cannot grant an extension on a closed case.");
            return;
        }

        const currentDeadline = new Date(currentCase.complianceDeadline);
        if (isNaN(currentDeadline.getTime())) {
            alert("The current compliance deadline is invalid. Cannot grant extension.");
            return;
        }

        currentDeadline.setDate(currentDeadline.getDate() + days);
        const formattedNewDeadline = currentDeadline.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

        const noteText = `Compliance deadline extended by ${days} day(s). New deadline: ${formattedNewDeadline}.`;
        const note = { date: today, text: noteText };

        const updatedCase = {
            ...currentCase,
            complianceDeadline: formattedNewDeadline,
            evidence: {
                ...currentCase.evidence,
                notes: [note, ...currentCase.evidence.notes]
            }
        };

        setCurrentCase(updatedCase);
        onUpdate(updatedCase);
        setExtensionDays('7'); // Reset to default
    };

    const handleReopenForAbatement = () => {
        if (!window.confirm("Are you sure you want to re-open this case and send it to abatement? The case status will be changed to 'PENDING_ABATEMENT'.")) return;

        const today = new Date().toLocaleString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
        const note = { date: today, text: "Case re-opened by user and forwarded for abatement." };

        const updatedCase = {
            ...currentCase,
            status: 'PENDING_ABATEMENT' as const,
            evidence: {
                ...currentCase.evidence,
                notes: [note, ...currentCase.evidence.notes]
            }
        };

        setCurrentCase(updatedCase);
        onUpdate(updatedCase);
    };

    const handleDeleteCase = () => {
        if (window.confirm('Are you sure you want to permanently delete this case? This action cannot be undone.')) {
            onDelete(currentCase.id);
        }
    };

    const getStatusConfig = (status: string) => {
        switch (status) {
            case 'PENDING_ABATEMENT':
                return { label: 'Pending Abatement', style: { backgroundColor: '#f3e5f5', color: '#6c3483', borderLeft: '6px solid #9b59b6' } };
            case 'CONTINUAL_ABATEMENT':
                return { label: 'Continual Abatement', style: { backgroundColor: '#6c3483', color: 'white', borderLeft: '6px solid #4a235a' } };
            case 'CLOSED':
                return { label: 'Closed', style: { backgroundColor: '#e9ecef', color: '#495057', borderLeft: '6px solid #ced4da' } };
            case 'FAILURE-NOTICED':
                 return { label: 'Failure Noticed', style: { backgroundColor: '#fdecea', color: '#c0392b', borderLeft: '6px solid #e74c3c' } };
            default:
                 if (getCaseTimeStatus(currentCase) === 'overdue') {
                     return { label: 'Active (Overdue)', style: { backgroundColor: '#fff3cd', color: '#856404', borderLeft: '6px solid #ffc107' } };
                 }
                 return { label: 'Active', style: { backgroundColor: '#d4edda', color: '#155724', borderLeft: '6px solid #28a745' } };
        }
    };

    const statusConfig = getStatusConfig(currentCase.status);

    return (
        <>
            {showFollowUpCamera && <CameraView 
                mode="single-case" 
                onDone={(p) => { 
                    setFollowUpPhotos(prev => [...prev, ...p]); 
                    setShowFollowUpCamera(false); 
                }} 
                onCancel={() => setShowFollowUpCamera(false)} 
            />}
            <div className="tab-content">
                <div className="viewing-header no-print">
                    <button onClick={onBack} className="button secondary-action">&larr; Back to List</button>
                    <button className="button secondary-action" onClick={handleDownloadArchive} disabled={isArchiving}>
                        {isArchiving ? <span className="loader" style={{borderTopColor: 'white', borderLeftColor: 'white', width: '1em', height: '1em', borderWidth: '2px'}} /> : 'Download Case Archive (ZIP)'}
                    </button>
                </div>

                <div className="card" style={{ marginBottom: '1.5rem', padding: '1rem', ...statusConfig.style }}>
                    <h2 style={{ margin: 0, borderBottom: 'none', fontSize: '1.5rem', color: 'inherit' }}>
                        {statusConfig.label.toUpperCase()}
                    </h2>
                </div>

                {isCaseOverdue && (
                    <div className="card no-print">
                        <h2>Compliance Follow-up</h2>
                        <QuickInput
                            label="Follow-up Notes"
                            value={followUpNotes}
                            onChange={setFollowUpNotes}
                            options={FOLLOW_UP_NOTES}
                            placeholder="e.g., Property has been mowed. Debris remains."
                            multiline={true}
                        />
                        <h4>Follow-up Photos ({followUpPhotos.length})</h4>
                        <div className="photo-gallery">{followUpPhotos.map((p, i) => <div key={i} className="photo-thumbnail"><img src={p.dataUrl} alt={`Follow-up photo ${i+1}`}/></div>)}</div>
                        <div className="button-group" style={{marginTop: '1rem', marginBottom: '1.5rem'}}>
                            <button type="button" className="button" onClick={() => setShowFollowUpCamera(true)}>Take Photos</button>
                        </div>
                        {followUpError && <p className="error-message">{followUpError}</p>}
                        <div className="button-group" style={{justifyContent: 'space-between', flexWrap: 'wrap'}}>
                             <button className="button danger-action" onClick={() => handleSaveFollowUp('ABATEMENT')} disabled={isSavingFollowUp}>
                                {isSavingFollowUp ? <span className="loader"/> : 'Forward for Abatement'}
                            </button>
                            <button className="button primary-action" style={{backgroundColor: 'var(--success-color)'}} onClick={() => handleSaveFollowUp('RESOLVE')} disabled={isSavingFollowUp}>
                               {isSavingFollowUp ? <span className="loader"/> : 'Mark as Resolved'}
                            </button>
                        </div>
                    </div>
                )}

                {currentCase.status === 'PENDING_ABATEMENT' && (
                    <AbatementManager caseData={currentCase} onUpdate={(updatedCase) => {
                        onUpdate(updatedCase);
                        setCurrentCase(updatedCase);
                    }} />
                )}


                {currentCase.ownerInfoStatus === 'UNKNOWN' && (
                    <div className="card no-print">
                        <h2>Add Owner Information</h2>
                        <div className="warning-box">This case is pending owner information.</div>
                        <div className="form-group"><label>Owner Name</label><input type="text" value={ownerInfoEdit.name} onChange={e => setOwnerInfoEdit({...ownerInfoEdit, name: e.target.value})} /></div>
                        <div className="form-group">
                            <label>Mailing Address</label>
                            <textarea value={ownerInfoEdit.mailingAddress} onChange={e => setOwnerInfoEdit({...ownerInfoEdit, mailingAddress: e.target.value})}></textarea>
                            <p className="helper-text">For multi-line addresses on envelopes, use the Enter/Return key for line breaks.</p>
                        </div>
                        <button className="button primary-action" onClick={handleSaveOwnerInfo}>Save Owner Info</button>
                    </div>
                )}
                <div className="card">
                    <h2>Property &amp; Owner Details</h2>

                    {isEditingAddress ? (
                        <div className="no-print">
                            <div className="form-group">
                                <label>Street Address</label>
                                <input type="text" value={addressEdit.street} onChange={e => setAddressEdit({...addressEdit, street: e.target.value})} />
                            </div>
                            <div className="button-group">
                                <button className="button" onClick={handleSaveAddress}>Save Address</button>
                                <button className="button secondary-action" onClick={handleCancelEditAddress}>Cancel</button>
                            </div>
                        </div>
                    ) : (
                        <div className="form-group readonly">
                            <label style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <span>Property Address</span>
                                <button className="button inline-action no-print" onClick={() => setIsEditingAddress(true)}>Edit</button>
                            </label>
                            <div className="form-value">{currentCase.address.street}</div>
                        </div>
                    )}

                    {isEditingOwnerInfo ? (
                        <div className="no-print" style={{marginTop: '1.5rem'}}>
                            <h4>Edit Owner Information</h4>
                            <div className="form-group">
                                <label>Owner Name</label>
                                <input type="text" value={ownerInfoEdit.name} onChange={e => setOwnerInfoEdit({...ownerInfoEdit, name: e.target.value})} />
                            </div>
                            <div className="form-group">
                                <label>Mailing Address</label>
                                <textarea value={ownerInfoEdit.mailingAddress} onChange={e => setOwnerInfoEdit({...ownerInfoEdit, mailingAddress: e.target.value})}></textarea>
                                <p className="helper-text">For multi-line addresses on envelopes, use the Enter/Return key for line breaks.</p>
                            </div>
                            <div className="button-group">
                                <button className="button" onClick={handleSaveOwnerInfo}>Save Changes</button>
                                <button className="button secondary-action" onClick={handleCancelEditOwnerInfo}>Cancel</button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <div className="form-group readonly">
                                <label style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span>Owner</span>
                                    {currentCase.ownerInfoStatus === 'KNOWN' &&
                                        <button className="button inline-action no-print" onClick={() => { setOwnerInfoEdit(currentCase.ownerInfo); setIsEditingOwnerInfo(true); }}>Edit</button>
                                    }
                                </label>
                                <div className="form-value">{currentCase.ownerInfo.name || 'N/A'}</div>
                            </div>
                            <div className="form-group readonly">
                                <label style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span>Owner Mailing Address</span>
                                    {currentCase.ownerInfo.mailingAddress && <button className="button inline-action no-print" onClick={handleGenerateEnvelope} disabled={isGeneratingEnvelope}>{isGeneratingEnvelope ? <span className="loader"/> : 'Print Envelope'}</button>}
                                </label>
                                <div className="form-value">{currentCase.ownerInfo.mailingAddress || 'N/A'}</div>
                            </div>
                        </>
                    )}
                </div>
                 <div className="card">
                    <h2>Case Management</h2>
                    {isEditingDates ? (
                        <div className="no-print">
                            <h4>Edit Case Dates</h4>
                            <div className="form-group">
                                <label>Date Created</label>
                                <input type="date" value={datesEdit.dateCreated} onChange={e => setDatesEdit({...datesEdit, dateCreated: e.target.value})} />
                            </div>
                            <div className="form-group">
                                <label>Compliance Deadline</label>
                                <input type="date" value={datesEdit.complianceDeadline} onChange={e => setDatesEdit({...datesEdit, complianceDeadline: e.target.value})} />
                            </div>
                            <div className="button-group">
                                <button className="button" onClick={handleSaveDates}>Save Dates</button>
                                <button className="button secondary-action" onClick={handleCancelEditDates}>Cancel</button>
                            </div>
                        </div>
                    ) : (
                        <div className="form-group readonly">
                            <label style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <span>Timeline</span>
                                <button className="button inline-action no-print" onClick={handleEditDates}>Edit Dates</button>
                            </label>
                            <div className="form-value">
                                <strong>Created:</strong> {currentCase.dateCreated}<br />
                                <strong>Deadline:</strong> {currentCase.complianceDeadline}
                            </div>
                        </div>
                    )}
                    <div style={{marginTop: '2rem'}}>
                        {(isGenerating || isGeneratingEnvelope) && <div className="status-message" style={{backgroundColor: '#eaf5ff'}}><div style={{display: 'inline-block', verticalAlign: 'middle', marginRight: '0.5rem'}} className="loader inline-loader"></div> Generating document(s)... Please wait.</div>}
                        {generationMessage && <div className="success-message">{generationMessage}</div>}
                        {generationError && <div className="error-banner">{generationError}</div>}
                        <div className="button-group no-print">
                            <button className="button" onClick={() => handleGenerateNotice('INITIAL')} disabled={isGenerating || isGeneratingEnvelope}>Generate Initial Notice</button>
                            <button className="button danger-action" onClick={() => handleGenerateNotice('FAILURE')} disabled={isGenerating || isGeneratingEnvelope}>Issue Abatement Notice</button>
                        </div>
                        <div className="button-group no-print" style={{marginTop: '0.75rem'}}>
                            <button className="button secondary-action" onClick={() => handleGenerateNotice('DILAPIDATED')} disabled={isGenerating || isGeneratingEnvelope}>Dilapidated Structure Notice</button>
                            <button className="button secondary-action" onClick={() => handleGenerateNotice('BOARDING')} disabled={isGenerating || isGeneratingEnvelope}>Board &amp; Secure Notice</button>
                        </div>
                    </div>
                    <h3 style={{marginTop: '1.5rem'}}>Case History & Notes</h3>
                    <div className="no-print" style={{marginBottom: '1rem'}}>
                        <QuickInput
                            value={newNote}
                            onChange={setNewNote}
                            placeholder="Add a new note..."
                            options={COMMON_NOTES}
                            multiline={false}
                        />
                        <div style={{textAlign: 'right', marginTop: '0.5rem'}}>
                             <button className="button" onClick={handleAddNote}>Save Note</button>
                        </div>
                    </div>

                    {currentCase.followUps?.map((followUp, index) => (
                        <div key={`followup-${index}`} className="note" style={{background: '#f9f2ff', border: '1px solid #e0cffc'}}>
                            <div className="note-date">{followUp.date} - <strong>Follow-up Inspection</strong></div>
                            <p>{followUp.notes}</p>
                            {followUp.photos && followUp.photos.length > 0 && (
                                <div className="photo-gallery" style={{marginTop: '0.5rem'}}>
                                    {followUp.photos.map((photo, pIndex) => (
                                        <div key={pIndex} className="photo-thumbnail">
                                            <img src={photo.url} alt={`Follow-up photo ${pIndex + 1}`} />
                                            <a
                                                href={photo.webViewLink}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="button download-photo"
                                                title="Open Photo in Google Drive"
                                            >
                                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"></path><polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg>
                                            </a>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ))}

                    {currentCase.evidence.notes.map((note, index) => <div key={index} className="note"><div className="note-date">{note.date}</div>{note.text}</div>)}
                </div>

                {currentCase.evidence.photos && currentCase.evidence.photos.length > 0 && (
                    <div className="card">
                        <h3>Evidence Photos</h3>
                        <div className="photo-gallery">
                            {currentCase.evidence.photos.map((photo, index) => (
                                <div key={index} className="photo-thumbnail">
                                    <img src={photo.url} alt={`Evidence photo ${index + 1}`} />
                                    <a
                                        href={photo.webViewLink}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="button download-photo"
                                        title="Open Photo in Google Drive"
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"></path><polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg>
                                    </a>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {currentCase.notices.length > 0 && (
                    <div className="card">
                        <h3>Generated Notices</h3>
                        {currentCase.notices.map((notice, i) => (
                            <div key={i} className="copyable-row" style={{ marginTop: '0.5rem' }}>
                               <span>
                                 <a href={notice.docUrl} target="_blank" rel="noopener noreferrer">{notice.title}</a>
                                 <div style={{fontSize: '0.8rem', color: 'var(--dark-gray)'}}>Generated: {notice.date}</div>
                               </span>
                               <button className="button copy-button" onClick={() => window.open(notice.docUrl, '_blank')}>Open</button>
                            </div>
                        ))}
                    </div>
                )}

                <div className="card no-print">
                    <h3>Case Actions</h3>
                    <div style={{ marginTop: '1rem', paddingTop: '1rem', borderTop: '1px solid var(--light-gray)' }}>
                        <h4>Mailing</h4>
                        <button
                            className="button"
                            onClick={handleToggleQueue}
                            disabled={!currentCase.ownerInfo.mailingAddress}
                        >
                            {isInQueue ? 'Remove from Certificate Queue' : 'Add to Certificate Queue'}
                        </button>
                        {!currentCase.ownerInfo.mailingAddress && <p className="helper-text">A mailing address is required to add this to the certificate queue.</p>}
                    </div>
                    <div style={{ marginTop: '1rem', paddingTop: '1rem', borderTop: '1px solid var(--light-gray)' }}>
                        <h4>Grant Extension</h4>
                        <div className="form-group">
                            <label>Number of days to extend compliance deadline:</label>
                            <div className="input-with-button">
                                <input
                                    type="number"
                                    value={extensionDays}
                                    onChange={(e) => setExtensionDays(e.target.value)}
                                    min="1"
                                    style={{ maxWidth: '100px' }}
                                    disabled={currentCase.status === 'CLOSED'}
                                />
                                <button
                                    className="button"
                                    onClick={handleGrantExtension}
                                    disabled={currentCase.status === 'CLOSED'}
                                >
                                    Grant Extension
                                </button>
                            </div>
                        </div>
                    </div>
                    <div style={{ marginTop: '1rem', paddingTop: '1rem', borderTop: '1px solid var(--light-gray)' }}>
                         <div className="button-group" style={{flexWrap: 'wrap', justifyContent: 'flex-start'}}>
                            <button
                                className="button primary-action"
                                onClick={handleResolveCase}
                                disabled={currentCase.status === 'CLOSED'}
                                style={{backgroundColor: 'var(--success-color)', fontSize: '1rem', padding: '0.8rem 1rem'}}
                            >
                                Mark as Resolved
                            </button>
                            <button
                                className="button danger-action"
                                onClick={handleDeleteCase}
                                style={{fontSize: '1rem', padding: '0.8rem 1rem'}}
                            >
                                Delete Case
                            </button>
                        </div>
                        {currentCase.status === 'CLOSED' && (
                            <div style={{marginTop: '1rem'}}>
                                <p style={{fontWeight: 500, marginBottom: '0.5rem'}}>This case is closed.</p>
                                <button
                                    className="button"
                                    onClick={handleReopenForAbatement}
                                    style={{backgroundColor: 'var(--warning-color)'}}
                                >
                                    Re-open for Abatement
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </>
    );
};

export default CaseDetails;

:root {
  --primary-color: #0284c7; /* Sky 600 */
  --primary-dark: #0369a1;
  --primary-light: #e0f2fe;

  --bg-color: #f1f5f9;      /* Slate 100 */
  --card-bg: #ffffff;

  --text-main: #1e293b;     /* Slate 800 */
  --text-secondary: #64748b; /* Slate 500 */
  --text-light: #94a3b8;    /* Slate 400 */

  --border-color: #e2e8f0;  /* Slate 200 */

  --danger-color: #ef4444;
  --success-color: #10b981;
  --warning-color: #f59e0b;
  --abatement-color: #8b5cf6;

  --shadow-sm: 0 1px 3px 0 rgb(0 0 0 / 0.1);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1);

  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-full: 9999px;

  --header-height: 64px;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

body {
  font-family: 'Roboto', system-ui, -apple-system, sans-serif;
  background-color: var(--bg-color);
  color: var(--text-main);
  line-height: 1.6;
  font-size: 16px;
  padding-bottom: 40px;
}

/* --- Header & Nav --- */
.app-header {
  background: white;
  height: var(--header-height);
  display: flex;
  align-items: center;
  padding: 0 1.5rem;
  position: sticky;
  top: 0;
  z-index: 100;
  border-bottom: 1px solid var(--border-color);
  box-shadow: var(--shadow-sm);
}

.app-header h1 {
  font-size: 1.25rem;
  font-weight: 700;
  color: var(--text-main);
  flex-grow: 1;
  text-align: center;
}

.main-nav {
  display: flex;
  flex-wrap: wrap; /* Fixed: Prevents horizontal overflow */
  justify-content: center;
  padding: 1rem;
  gap: 0.5rem;
  background-color: var(--bg-color);
  position: sticky;
  top: var(--header-height);
  z-index: 90;
}

.main-nav button {
  padding: 0.5rem 1rem;
  border: 1px solid transparent;
  background: white;
  color: var(--text-secondary);
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  border-radius: var(--radius-full);
  transition: all 0.2s;
  box-shadow: var(--shadow-sm);
  white-space: nowrap;
}

.main-nav button.active {
  background-color: var(--primary-color);
  color: white;
  box-shadow: var(--shadow-md);
}

/* --- Layout --- */
.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

#root {
  max-width: 800px;
  margin: 0 auto;
  width: 100%;
}

.main-content {
  padding: 1rem 1.25rem;
}

.tab-content {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
  animation: fadeIn 0.3s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

/* --- Cards --- */
.card {
  background: white;
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  padding: 1.5rem;
  border: 1px solid var(--border-color);
}

.card h2 {
  font-size: 1.25rem;
  margin-bottom: 1.25rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

/* --- Abatement Stepper --- */
.stepper {
  display: flex;
  justify-content: space-between;
  margin-bottom: 2rem;
  position: relative;
}
.stepper::before {
  content: '';
  position: absolute;
  top: 18px;
  left: 10%;
  right: 10%;
  height: 2px;
  background: var(--border-color);
  z-index: 0;
}
.step {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
  cursor: pointer;
}
.step-circle {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: white;
  border: 2px solid var(--border-color);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  margin-bottom: 0.5rem;
  transition: all 0.3s;
}
.step.active .step-circle {
  border-color: var(--abatement-color);
  background: var(--abatement-color);
  color: white;
  transform: scale(1.1);
}
.step.completed .step-circle {
  background: var(--success-color);
  border-color: var(--success-color);
  color: white;
}
.step-label {
  font-size: 0.75rem;
  font-weight: 700;
  text-transform: uppercase;
  color: var(--text-light);
}
.step.active .step-label { color: var(--abatement-color); }

/* --- Timer --- */
.timer-card {
  background: #1e293b;
  color: white;
  padding: 2rem;
  border-radius: var(--radius-lg);
  text-align: center;
  margin: 1.5rem 0;
}
.timer-count {
  font-size: 4rem;
  font-weight: 800;
  color: var(--primary-color);
  line-height: 1;
}
.timer-label {
  text-transform: uppercase;
  letter-spacing: 0.1em;
  font-size: 0.85rem;
  opacity: 0.8;
  margin-top: 0.5rem;
}

/* --- Lists --- */
.case-item {
  background: white;
  padding: 1.25rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow-sm);
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}
.case-item:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
  border-color: var(--primary-light);
}
.case-item::before {
  content: '';
  position: absolute;
  left: 0; top: 0; bottom: 0; width: 5px;
  background: var(--border-color);
}
.case-item.overdue::before { background: var(--warning-color); }
.case-item.abatement::before { background: var(--abatement-color); }
.case-item.closed { opacity: 0.7; }

/* --- Buttons --- */
.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.5rem;
  border-radius: var(--radius-md);
  border: none;
  background: var(--primary-color);
  color: white;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
  min-height: 48px;
}
.button:hover { background: var(--primary-dark); transform: translateY(-1px); }
.button:active { transform: translateY(0); }
.button:disabled { background: var(--text-light); opacity: 0.5; cursor: not-allowed; }

.button.secondary-action {
  background: white;
  color: var(--text-main);
  border: 1px solid var(--border-color);
}
.button.danger-action { background: var(--danger-color); }

.button-group {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

/* --- Forms --- */
.form-group { margin-bottom: 1.5rem; }
.form-group label {
  display: block;
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
input, textarea, select {
  width: 100%;
  padding: 0.75rem 1rem;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  font-size: 1rem;
  background: white;
  transition: border-color 0.2s;
}
input:focus { outline: none; border-color: var(--primary-color); }

.success-message { background: #dcfce7; color: #166534; padding: 1rem; border-radius: var(--radius-md); border: 1px solid #bbf7d0; }
.error-message { background: #fee2e2; color: #991b1b; padding: 1rem; border-radius: var(--radius-md); border: 1px solid #fecaca; }
.info-box { background: #e0f2fe; color: #075985; padding: 1rem; border-radius: var(--radius-md); }

/* Search Bar */
.search-bar { position: relative; margin-bottom: 1.5rem; }
.search-bar input { padding-left: 3rem; border-radius: var(--radius-full); box-shadow: var(--shadow-sm); }
.search-icon { position: absolute; left: 1rem; top: 50%; transform: translateY(-50%); color: var(--text-light); }

/* Photo Gallery */
.photo-gallery { display: flex; gap: 1rem; overflow-x: auto; padding-bottom: 1rem; }
.photo-thumbnail { width: 100px; height: 100px; flex-shrink: 0; border-radius: var(--radius-md); overflow: hidden; border: 1px solid var(--border-color); }
.photo-thumbnail img { width: 100%; height: 100%; object-fit: cover; }

@media print {
  .no-print { display: none !important; }
  .card { box-shadow: none; border: 1px solid #ddd; }
}

import React, { useState, useEffect } from 'react';
import { Case, PhotoWithMeta, AbatementDetails, EvidencePhoto } from '../types';
import { dataService, generateStatementOfCostDocument, generateNoticeOfLienDocument, generateCertificateOfLienDocument } from '../googleSheetsService';
import CameraView from './CameraView';

const AbatementManager: React.FC<{ caseData: Case; onUpdate: (updatedCase: Case) => void; }> = ({ caseData, onUpdate }) => {
    const [details, setDetails] = useState<AbatementDetails>(caseData.abatement || {});
    const [tempBeforePhotos, setTempBeforePhotos] = useState<PhotoWithMeta[]>([]);
    const [tempAfterPhotos, setTempAfterPhotos] = useState<PhotoWithMeta[]>([]);
    const [showCamera, setShowCamera] = useState<'before' | 'after' | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');
    const [overrideTimer, setOverrideTimer] = useState(false);

    // Navigation Step logic
    const getActiveStep = () => {
        if (details.certificateOfLienDocUrl || details.status === 'LIEN_CERTIFIED') return 4;
        if (details.noticeOfLienDocUrl || details.status === 'LIEN_FILED') return 3;
        if (details.statementOfCostDocUrl || details.status === 'STATEMENT_FILED') return 2;
        return 1;
    };

    const currentProcessStep = getActiveStep();
    const [viewStep, setViewStep] = useState(currentProcessStep);

    useEffect(() => {
        setViewStep(currentProcessStep);
    }, [currentProcessStep]);

    // Timer Calculation
    const getDaysRemaining = () => {
        if (!details.noticeOfLienDate) return 30;
        const start = new Date(details.noticeOfLienDate);
        const now = new Date();
        start.setHours(0,0,0,0);
        now.setHours(0,0,0,0);
        const diffTime = now.getTime() - start.getTime();
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
        return Math.max(0, 30 - diffDays);
    };

    const daysRemaining = getDaysRemaining();
    const isTimerDone = daysRemaining === 0;

    const updateDetails = (updates: Partial<AbatementDetails>) => {
        const newDetails = { ...details, ...updates };
        setDetails(newDetails);
    };

    const saveStepPhotos = async (type: 'before' | 'after') => {
        const photosToUpload = type === 'before' ? tempBeforePhotos : tempAfterPhotos;
        if (photosToUpload.length === 0) return;
        setIsSaving(true);
        setError('');
        try {
            const uploaded = await dataService.uploadAbatementPhotos(photosToUpload, caseData.caseId, type);
            const existing = details.photos?.[type] || [];
            const newDetails = { ...details, photos: { ...details.photos, [type]: [...existing, ...uploaded] } };
            setDetails(newDetails);
            onUpdate({ ...caseData, abatement: newDetails });
            if (type === 'before') setTempBeforePhotos([]);
            else setTempAfterPhotos([]);
        } catch(e: any) {
            setError(`Upload failed: ${e.message}`);
        } finally {
            setIsSaving(false);
        }
    };

    const handleGenerate = async (docType: 'statement' | 'lien' | 'certificate') => {
        setIsSaving(true);
        setError('');
        setMessage('');
        try {
            let updatedCase = { ...caseData, abatement: { ...details } };
            const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
            let result;

            if (docType === 'statement') {
                const { hours, employees } = details.costDetails || { hours: 0, employees: 0 };
                const total = (hours * employees * 25) + 50;
                updatedCase.abatement.costDetails = { type: 'mowing', hours, employees, rate: 25, adminFee: 50, total };
                updatedCase.abatement.statementOfCostDate = today;
                updatedCase.abatement.status = 'STATEMENT_FILED';
                result = await generateStatementOfCostDocument(updatedCase);
                updatedCase.abatement.statementOfCostDocUrl = result.docUrl;
            } 
            else if (docType === 'lien') {
                updatedCase.abatement.status = 'LIEN_FILED';
                updatedCase.abatement.noticeOfLienDate = today;
                result = await generateNoticeOfLienDocument(updatedCase);
                updatedCase.abatement.noticeOfLienDocUrl = result.docUrl;
            }
            else if (docType === 'certificate') {
                updatedCase.abatement.status = 'LIEN_CERTIFIED';
                result = await generateCertificateOfLienDocument(updatedCase);
                updatedCase.abatement.certificateOfLienDocUrl = result.docUrl;
                updatedCase.status = 'CONTINUAL_ABATEMENT';
            }

            setDetails(updatedCase.abatement);
            onUpdate(updatedCase);
            window.open(result.docUrl, '_blank');
            setMessage(`${docType.toUpperCase()} generated successfully.`);
        } catch (e: any) {
            setError(`Action failed: ${e.message}`);
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className="card" style={{ borderLeft: '6px solid var(--abatement-color)' }}>
            {showCamera && <CameraView mode="single-case" onCancel={() => setShowCamera(null)} onDone={(p) => {
                if (showCamera === 'before') setTempBeforePhotos(prev => [...prev, ...p]);
                else setTempAfterPhotos(prev => [...prev, ...p]);
                setShowCamera(null);
            }} />}

            <h2 style={{ color: 'var(--abatement-color)' }}>Abatement Process</h2>

            <div className="stepper">
                {[
                    { label: 'Document', step: 1 },
                    { label: 'Statement', step: 2 },
                    { label: 'Lien', step: 3 },
                    { label: 'Certify', step: 4 }
                ].map(s => (
                    <div key={s.step} className={`step ${viewStep === s.step ? 'active' : ''} ${currentProcessStep > s.step ? 'completed' : ''}`} onClick={() => setViewStep(s.step)}>
                        <div className="step-circle">{currentProcessStep > s.step ? '✓' : s.step}</div>
                        <div className="step-label">{s.label}</div>
                    </div>
                ))}
            </div>

            {error && <div className="error-message" style={{marginBottom: '1rem'}}>{error}</div>}
            {message && <div className="success-message" style={{marginBottom: '1rem'}}>{message}</div>}

            {viewStep === 1 && (
                <div className="tab-content">
                    <h3>Step 1: Document Work</h3>
                    <div className="form-group">
                        <label>Work Date</label>
                        <input type="date" value={details.workDate || ''} onChange={e => updateDetails({ workDate: e.target.value })} />
                    </div>
                    <div className="form-group">
                        <label>Hours Worked</label>
                        <input type="number" step="0.25" value={details.costDetails?.hours || ''} onChange={e => updateDetails({ costDetails: { ...details.costDetails, type: 'mowing', hours: +e.target.value, employees: details.costDetails?.employees || 1, rate: 25, adminFee: 50, total: 0 }})} />
                    </div>

                    <h4>Photos</h4>
                    <div className="button-group">
                        <button className="button secondary-action" onClick={() => setShowCamera('before')}>Take "Before" Photos</button>
                        <button className="button secondary-action" onClick={() => setShowCamera('after')}>Take "After" Photos</button>
                    </div>
                    {(tempBeforePhotos.length > 0 || tempAfterPhotos.length > 0) && (
                        <button className="button primary-action" onClick={() => { saveStepPhotos('before'); saveStepPhotos('after'); }} style={{marginTop: '1rem'}}>Upload New Photos</button>
                    )}

                    <button className="button full-width" onClick={() => setViewStep(2)} disabled={!details.workDate} style={{marginTop: '2rem'}}>Continue to Statement &rarr;</button>
                </div>
            )}

            {viewStep === 2 && (
                <div className="tab-content">
                    <h3>Step 2: Statement of Cost</h3>
                    <div className="info-box">
                        <p><strong>Work Date:</strong> {details.workDate}</p>
                        <p><strong>Labor:</strong> {details.costDetails?.hours} hrs x {details.costDetails?.employees} emp @ $25/hr</p>
                        <p><strong>Admin Fee:</strong> $50.00</p>
                        <p style={{fontSize: '1.25rem', fontWeight: 800, marginTop: '0.5rem'}}>TOTAL: ${(((details.costDetails?.hours || 0) * (details.costDetails?.employees || 0) * 25) + 50).toFixed(2)}</p>
                    </div>
                    <button className="button primary-action full-width" onClick={() => handleGenerate('statement')} disabled={isSaving}>
                        {isSaving ? 'Generating...' : 'Generate & Save Statement of Cost'}
                    </button>
                    {details.statementOfCostDocUrl && (
                        <button className="button secondary-action full-width" onClick={() => setViewStep(3)}>Continue to Lien Filing &rarr;</button>
                    )}
                </div>
            )}

            {viewStep === 3 && (
                <div className="tab-content">
                    <h3>Step 3: File Notice of Lien</h3>
                    <div className="form-group">
                        <label>Legal Description</label>
                        <textarea value={details.propertyInfo?.legalDescription || ''} onChange={e => updateDetails({ propertyInfo: {...details.propertyInfo, legalDescription: e.target.value}})} placeholder="Lot X, Block Y..."></textarea>
                    </div>
                    <button className="button primary-action full-width" onClick={() => handleGenerate('lien')} disabled={isSaving || !details.propertyInfo?.legalDescription}>
                        {isSaving ? 'Generating...' : 'Generate Notice of Lien'}
                    </button>
                    {details.noticeOfLienDocUrl && (
                        <button className="button secondary-action full-width" onClick={() => setViewStep(4)}>View Waiting Period &rarr;</button>
                    )}
                </div>
            )}

            {viewStep === 4 && (
                <div className="tab-content">
                    <h3>Step 4: Certificate of Lien</h3>

                    {!details.certificateOfLienDocUrl ? (
                        <>
                            <div className="timer-card">
                                <div className="timer-count">{daysRemaining}</div>
                                <div className="timer-label">{isTimerDone ? 'Ready to Certify' : 'Days Remaining in Waiting Period'}</div>
                            </div>

                            {!isTimerDone && !overrideTimer && (
                                <div className="warning-box" style={{textAlign: 'center', marginBottom: '1rem'}}>
                                    You must wait 30 days from <strong>{details.noticeOfLienDate}</strong> before certifying.
                                    <br/><button className="button secondary-action" style={{marginTop: '1rem', padding: '0.25rem 0.5rem', minHeight: 'auto'}} onClick={() => setOverrideTimer(true)}>Admin Override</button>
                                </div>
                            )}

                            <button className="button primary-action full-width" onClick={() => handleGenerate('certificate')} disabled={isSaving || (!isTimerDone && !overrideTimer)}>
                                {isSaving ? 'Generating...' : 'Generate Certificate of Lien'}
                            </button>
                        </>
                    ) : (
                        <div className="success-message">
                            <h4>Process Complete</h4>
                            <p>Certificate of Lien was generated on {details.certificateOfLienDocUrl}. Case is now in Continual Abatement.</p>
                            <a href={details.certificateOfLienDocUrl} target="_blank" rel="noreferrer" className="button full-width" style={{marginTop: '1rem'}}>Open Certificate</a>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default AbatementManager;

import React, { useState, useEffect } from 'react';
import { Case, NoticePurpose, PhotoWithMeta, EvidencePhoto, FollowUp } from '../types';
import { generateNoticeDocument, generateEnvelopeDocument } from '../googleSheetsService';
import { GOOGLE_API_LIBRARY_URL, COMPLIANCE_DAYS, COMMON_NOTES, FOLLOW_UP_NOTES } from '../constants';
import { getCaseTimeStatus } from '../utils';
import { dataService } from '../googleSheetsService';
import { markTaskComplete, addToCertMailQueue, getCertMailQueue, removeFromCertMailQueue } from '../dailyTaskService';
import AbatementManager from './AbatementManager';
import CameraView from './CameraView';
import QuickInput from './QuickInput';

const CaseDetails: React.FC<{ caseData: Case; onBack: () => void; onUpdate: (updatedCase: Case) => void; onDelete: (caseId: string) => void; }> = ({ caseData, onBack, onUpdate, onDelete }) => {
    const [currentCase, setCurrentCase] = useState(caseData);
    const [isGenerating, setIsGenerating] = useState(false);
    const [genError, setGenError] = useState('');
    const [genMsg, setGenMsg] = useState('');

    const statusClass = getCaseTimeStatus(currentCase);
    const isOverdue = statusClass === 'overdue' && currentCase.status !== 'CLOSED' && currentCase.status !== 'PENDING_ABATEMENT';

    const handleGenerate = async (purpose: NoticePurpose) => {
        setIsGenerating(true);
        setGenError('');
        setGenMsg('');
        try {
            const docs = await generateNoticeDocument(purpose, currentCase);
            docs.forEach(d => window.open(d.docUrl, '_blank'));

            const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
            const updatedCase = { ...currentCase };
            updatedCase.notices.unshift({ title: docs[0].title, docUrl: docs[0].docUrl, date: today });

            if (purpose === 'FAILURE') updatedCase.status = 'FAILURE-NOTICED';

            setCurrentCase(updatedCase);
            onUpdate(updatedCase);
            setGenMsg('Notice generated and opened.');
        } catch (e: any) {
            setGenError(`Failed: ${e.message}`);
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="tab-content">
            <button onClick={onBack} className="button secondary-action no-print">&larr; Back to List</button>

            <div className={`card ${statusClass}`} style={{ borderLeft: '8px solid' }}>
                <h1 style={{ marginBottom: '0.5rem' }}>{currentCase.address.street}</h1>
                <p style={{ color: 'var(--text-secondary)' }}>Case #{currentCase.caseId} | {currentCase.status.replace('-', ' ')}</p>
            </div>

            {currentCase.status === 'PENDING_ABATEMENT' && (
                <AbatementManager caseData={currentCase} onUpdate={onUpdate} />
            )}

            <div className="card no-print">
                <h2>Generate Notices</h2>
                <div className="button-group">
                    <button className="button" onClick={() => handleGenerate('INITIAL')} disabled={isGenerating}>Initial Notice</button>
                    <button className="button danger-action" onClick={() => handleGenerate('FAILURE')} disabled={isGenerating}>Issue Abatement Notice</button>
                </div>
                <div className="button-group" style={{ marginTop: '0.75rem' }}>
                    <button className="button secondary-action" onClick={() => handleGenerate('DILAPIDATED')} disabled={isGenerating}>Dilapidated House Notice</button>
                    <button className="button secondary-action" onClick={() => handleGenerate('BOARDING')} disabled={isGenerating}>Board & Secure Notice</button>
                </div>
                {genError && <div className="error-message" style={{marginTop: '1rem'}}>{genError}</div>}
                {genMsg && <div className="success-message" style={{marginTop: '1rem'}}>{genMsg}</div>}
            </div>

            <div className="card">
                <h2>Owner & Property Details</h2>
                <div className="form-group readonly">
                    <label>Property Address</label>
                    <div className="form-value">{currentCase.address.street}</div>
                </div>
                <div className="form-group readonly">
                    <label>Owner Info</label>
                    <div className="form-value">
                        {currentCase.ownerInfo.name}<br/>
                        {currentCase.ownerInfo.mailingAddress}
                    </div>
                </div>
                <div className="form-group readonly">
                    <label>Violation</label>
                    <div className="form-value">
                        <strong>{currentCase.violation.type}</strong><br/>
                        {currentCase.violation.description}
                    </div>
                </div>
            </div>

            <div className="card no-print">
                <button className="button danger-action full-width" onClick={() => onDelete(currentCase.id)}>Delete Entire Case File</button>
            </div>
        </div>
    );
};

export default CaseDetails;

import React, { useState, useEffect } from 'react';
import { AppConfig } from '../types';
import { getConfig, saveConfig } from '../config';

const TemplateManager: React.FC = () => {
    const [config, setConfig] = useState<AppConfig | null>(null);
    const [urls, setUrls] = useState({
        INITIAL: '', FAILURE: '', DILAPIDATED: '', BOARDING: '', 
        envelope: '', certMail: '', cost: '', lien: '', certLien: ''
    });
    const [status, setStatus] = useState('');

    useEffect(() => {
        getConfig().then(cfg => {
            if (cfg) {
                setConfig(cfg);
                setUrls({
                    INITIAL: cfg.google?.templateUrls?.INITIAL || '',
                    FAILURE: cfg.google?.templateUrls?.FAILURE || '',
                    DILAPIDATED: cfg.google?.templateUrls?.DILAPIDATED || '',
                    BOARDING: cfg.google?.templateUrls?.BOARDING || '',
                    envelope: cfg.google?.envelopeTemplateUrl || '',
                    certMail: cfg.google?.certificateOfMailTemplateUrl || '',
                    cost: cfg.google?.statementOfCostTemplateUrl || '',
                    lien: cfg.google?.noticeOfLienTemplateUrl || '',
                    certLien: cfg.google?.certificateOfLienTemplateUrl || ''
                });
            }
        });
    }, []);

    const handleSave = async () => {
        if (!config) return;
        const newConfig: AppConfig = {
            ...config,
            google: {
                ...config.google!,
                templateUrls: {
                    INITIAL: urls.INITIAL, FAILURE: urls.FAILURE, 
                    DILAPIDATED: urls.DILAPIDATED, BOARDING: urls.BOARDING
                },
                envelopeTemplateUrl: urls.envelope,
                certificateOfMailTemplateUrl: urls.certMail,
                statementOfCostTemplateUrl: urls.cost,
                noticeOfLienTemplateUrl: urls.lien,
                certificateOfLienTemplateUrl: urls.certLien
            }
        };
        await saveConfig(newConfig);
        setStatus('Saved successfully!');
    };

    return (
        <div className="tab-content">
            <div className="card">
                <h2>Manage Document Templates</h2>
                <div className="form-group">
                    <label>Initial Notice URL</label>
                    <input value={urls.INITIAL} onChange={e => setUrls({...urls, INITIAL: e.target.value})} />
                </div>
                <div className="form-group">
                    <label>Abatement (Failure) Notice URL</label>
                    <input value={urls.FAILURE} onChange={e => setUrls({...urls, FAILURE: e.target.value})} />
                </div>
                <div className="form-group">
                    <label>Dilapidated House Notice URL</label>
                    <input value={urls.DILAPIDATED} onChange={e => setUrls({...urls, DILAPIDATED: e.target.value})} />
                </div>
                <div className="form-group">
                    <label>Board & Secure Notice URL</label>
                    <input value={urls.BOARDING} onChange={e => setUrls({...urls, BOARDING: e.target.value})} />
                </div>
                <hr style={{margin: '2rem 0', opacity: 0.2}}/>
                <div className="form-group">
                    <label>Notice of Lien URL</label>
                    <input value={urls.lien} onChange={e => setUrls({...urls, lien: e.target.value})} />
                </div>
                <div className="form-group">
                    <label>Certificate of Lien URL</label>
                    <input value={urls.certLien} onChange={e => setUrls({...urls, certLien: e.target.value})} />
                </div>
                <button className="button primary-action" onClick={handleSave}>Save All Templates</button>
                {status && <div className="success-message" style={{marginTop: '1rem'}}>{status}</div>}
            </div>
        </div>
    );
};

export default TemplateManager;
